     1→import { PrecisionClock } from './PrecisionClock';
     2→import { TimingDriftDetector } from './TimingDriftDetector';
     3→
     4→/**
     5→ * Hardware capabilities test results
     6→ */
     7→export interface HardwareCapabilities {
     8→  webGL2Supported: boolean;
     9→  webGL1Supported: boolean;
