    22→ * Timing validation results
    23→ */
    24→export interface TimingValidationResult {
    25→  deviceCapabilities: HardwareCapabilities;
    26→  fpsMetrics: {
    27→    targetFps: number;
    28→    actualFps: number;
    29→    fpsVariance: number;
    30→    frameTimeVariance: number;
    31→    droppedFrames: number;
    32→    testDuration: number;
    33→  };
    34→  memoryMetrics: {
    35→    heapUsed: number;
    36→    heapTotal: number;
    37→    heapLimit: number;
    38→    externalMemory: number;
    39→  };
    40→  timingPrecision: {
    41→    clockResolution: number;
    42→    driftRate: number;
    43→    jitter: number;
    44→    maxDeviation: number;
    45→  };
    46→  compatibilityMatrix: {
    47→    canRun2msPrecision: boolean;
    48→    canRun5msPrecision: boolean;
    49→    canRun16msPrecision: boolean;
    50→    recommendedFrameRate: number;
    51→    warnings: string[];
    52→  };
    53→}
    54→
    55→/**
    56→ * Hardware timing validation suite for validating <2ms precision claims
    57→ */
    58→export class HardwareTimingValidator {
    59→  private clock: PrecisionClock;
    60→  private driftDetector: TimingDriftDetector;
    61→  
    62→  constructor() {
    63→    this.clock = new PrecisionClock();
    64→    this.driftDetector = new TimingDriftDetector();
    65→  }
    66→
    67→  /**
    68→   * Detect hardware capabilities
    69→   */
    70→  private detectCapabilities(): HardwareCapabilities {
    71→    const canvas = document.createElement('canvas');
    72→    const gl2 = canvas.getContext('webgl2');
    73→    const gl1 = !gl2 ? canvas.getContext('webgl') : null;
    74→    
    75→    // Measure performance.now() resolution
    76→    const perfSamples: number[] = [];
    77→    for (let i = 0; i < 1000; i++) {
    78→      perfSamples.push(performance.now());
    79→    }
    80→    
    81→    // Calculate minimum non-zero delta
    82→    const deltas: number[] = [];
    83→    for (let i = 1; i < perfSamples.length; i++) {
    84→      const delta = perfSamples[i] - perfSamples[i - 1];
    85→      if (delta > 0) deltas.push(delta);
    86→    }
    87→    
    88→    const performanceNowResolution = deltas.length > 0 
    89→      ? Math.min(...deltas)
    90→      : 0.001; // Fallback to 1 microsecond
    91→    
    92→    return {
    93→      webGL2Supported: !!gl2,
    94→      webGL1Supported: !!gl1 || !!gl2,
    95→      canvasSupported: !!canvas.getContext('2d'),
    96→      requestVideoFrameCallbackSupported: 'requestVideoFrameCallback' in HTMLVideoElement.prototype,
    97→      audioContextSupported: typeof AudioContext !== 'undefined',
    98→      performanceNowResolution,
    99→      displayRefreshRate: screen.height && 'refreshRate' in screen ? (screen as any).refreshRate : 60,
   100→      hardwareConcurrency: navigator.hardwareConcurrency || 1,
   101→      deviceMemory: (navigator as any).deviceMemory,
   102→      userAgent: navigator.userAgent,
   103→      platform: navigator.platform
   104→    };
   105→  }
   106→
   107→  /**
   108→   * Test FPS stability and frame timing
   109→   */
   110→  private async testFrameRateStability(targetFps: number, durationMs: number): Promise<{
   111→    actualFps: number;
   112→    fpsVariance: number;
   113→    frameTimeVariance: number;
   114→    droppedFrames: number;
   115→  }> {
   116→    const frameTimes: number[] = [];
   117→    const targetFrameTime = 1000 / targetFps;
   118→    let lastTime = performance.now();
   119→    let frameCount = 0;
   120→    let droppedFrames = 0;
   121→    
   122→    return new Promise((resolve) => {
   123→      const startTime = performance.now();
   124→      
   125→      const frame = () => {
   126→        const currentTime = performance.now();
   127→        const deltaTime = currentTime - lastTime;
   128→        
   129→        frameTimes.push(deltaTime);
   130→        
   131→        // Check for dropped frames (frame time > 1.5x target)
   132→        if (deltaTime > targetFrameTime * 1.5) {
   133→          droppedFrames++;
   134→        }
   135→        
   136→        lastTime = currentTime;
   137→        frameCount++;
   138→        
   139→        if (currentTime - startTime < durationMs) {
   140→          requestAnimationFrame(frame);
   141→        } else {
   142→          // Calculate metrics
   143→          const actualFps = frameCount / ((currentTime - startTime) / 1000);
   144→          
   145→          // Calculate variance
   146→          const avgFrameTime = frameTimes.reduce((a, b) => a + b, 0) / frameTimes.length;
   147→          const frameTimeVariance = Math.sqrt(
   148→            frameTimes.reduce((sum, time) => sum + Math.pow(time - avgFrameTime, 2), 0) / frameTimes.length
   149→          );
   150→          
   151→          const fpsValues = frameTimes.map(t => 1000 / t);
   152→          const avgFps = fpsValues.reduce((a, b) => a + b, 0) / fpsValues.length;
   153→          const fpsVariance = Math.sqrt(
   154→            fpsValues.reduce((sum, fps) => sum + Math.pow(fps - avgFps, 2), 0) / fpsValues.length
   155→          );
   156→          
   157→          resolve({
   158→            actualFps,
   159→            fpsVariance,
   160→            frameTimeVariance,
   161→            droppedFrames
   162→          });
   163→        }
   164→      };
   165→      
   166→      requestAnimationFrame(frame);
   167→    });
   168→  }
   169→
   170→  /**
   171→   * Test memory usage patterns
   172→   */
   173→  private getMemoryMetrics(): {
   174→    heapUsed: number;
   175→    heapTotal: number;
   176→    heapLimit: number;
   177→    externalMemory: number;
   178→  } {
   179→    if ('memory' in performance && (performance as any).memory) {
   180→      const memory = (performance as any).memory;
   181→      return {
   182→        heapUsed: memory.usedJSHeapSize || 0,
   183→        heapTotal: memory.totalJSHeapSize || 0,
   184→        heapLimit: memory.jsHeapSizeLimit || 0,
   185→        externalMemory: 0 // Not available in browser
   186→      };
   187→    }
   188→    
   189→    // Fallback for browsers without memory API
   190→    return {
   191→      heapUsed: 0,
   192→      heapTotal: 0,
   193→      heapLimit: 0,
   194→      externalMemory: 0
   195→    };
   196→  }
   197→
   198→  /**
   199→   * Test timing precision using PrecisionClock
   200→   */
   201→  private async testTimingPrecision(): Promise<{
   202→    clockResolution: number;
   203→    driftRate: number;
   204→    jitter: number;
   205→    maxDeviation: number;
   206→  }> {
   207→    await this.clock.initialize();
   208→    
   209→    // Test clock resolution
   210→    const timestamps: number[] = [];
   211→    for (let i = 0; i < 1000; i++) {
   212→      timestamps.push(this.clock.now().monotonic);
   213→    }
   214→    
   215→    // Calculate minimum non-zero delta for resolution
   216→    const deltas: number[] = [];
   217→    for (let i = 1; i < timestamps.length; i++) {
   218→      const delta = timestamps[i] - timestamps[i - 1];
   219→      if (delta > 0) deltas.push(delta);
   220→    }
   221→    
   222→    const clockResolution = deltas.length > 0 
   223→      ? Math.min(...deltas) * 1000 // Convert to microseconds
   224→      : 1; // 1 microsecond fallback
   225→    
   226→    // Test drift over 5 seconds
   227→    const driftStartTime = this.clock.now();
   228→    const perfStartTime = performance.now();
   229→    
   230→    await new Promise(resolve => setTimeout(resolve, 5000));
   231→    
   232→    const driftEndTime = this.clock.now();
   233→    const perfEndTime = performance.now();
   234→    
   235→    const clockElapsed = driftEndTime.monotonic - driftStartTime.monotonic;
   236→    const perfElapsed = (perfEndTime - perfStartTime) / 1000;
   237→    const driftRate = Math.abs(clockElapsed - perfElapsed) / perfElapsed;
   238→    
   239→    // Test jitter by measuring timing intervals
   240→    const intervalDeltas: number[] = [];
   241→    let lastInterval = this.clock.now().monotonic;
   242→    
   243→    for (let i = 0; i < 100; i++) {
   244→      await new Promise(resolve => setTimeout(resolve, 10));
   245→      const current = this.clock.now().monotonic;
   246→      intervalDeltas.push((current - lastInterval) * 1000 - 10); // Expected 10ms, convert to ms
   247→      lastInterval = current;
   248→    }
   249→    
   250→    const avgDelta = intervalDeltas.reduce((a, b) => a + b, 0) / intervalDeltas.length;
   251→    const jitter = Math.sqrt(
   252→      intervalDeltas.reduce((sum, delta) => sum + Math.pow(delta - avgDelta, 2), 0) / intervalDeltas.length
   253→    );
   254→    
   255→    const maxDeviation = Math.max(...intervalDeltas.map(d => Math.abs(d)));
   256→    
   257→    return {
   258→      clockResolution,
   259→      driftRate,
   260→      jitter,
   261→      maxDeviation
   262→    };
   263→  }
   264→
   265→  /**
   266→   * Determine compatibility based on test results
   267→   */
   268→  private determineCompatibility(
   269→    capabilities: HardwareCapabilities,
   270→    fpsMetrics: any,
   271→    timingPrecision: any
   272→  ): {
   273→    canRun2msPrecision: boolean;
   274→    canRun5msPrecision: boolean;
   275→    canRun16msPrecision: boolean;
   276→    recommendedFrameRate: number;
   277→    warnings: string[];
   278→  } {
   279→    const warnings: string[] = [];
   280→    
   281→    // Check WebGL support
   282→    if (!capabilities.webGL2Supported && !capabilities.webGL1Supported) {
   283→      warnings.push('No WebGL support detected - performance will be limited');
   284→    }
   285→    
   286→    // Check frame rate stability
   287→    if (fpsMetrics.droppedFrames > 5) {
   288→      warnings.push(`High dropped frame count (${fpsMetrics.droppedFrames}) - may impact timing precision`);
   289→    }
   290→    
   291→    if (fpsMetrics.frameTimeVariance > 2) {
   292→      warnings.push(`High frame time variance (${fpsMetrics.frameTimeVariance.toFixed(2)}ms) - timing may be unstable`);
   293→    }
   294→    
   295→    // Check timing precision
   296→    if (timingPrecision.clockResolution > 100) {
   297→      warnings.push(`Low clock resolution (${timingPrecision.clockResolution.toFixed(0)}μs) - may limit precision`);
   298→    }
   299→    
   300→    if (timingPrecision.jitter > 1) {
   301→      warnings.push(`High timing jitter (${timingPrecision.jitter.toFixed(2)}ms) - precision degraded`);
   302→    }
   303→    
   304→    // Determine precision capabilities
   305→    const canRun2msPrecision = 
   306→      capabilities.audioContextSupported &&
   307→      capabilities.webGL2Supported &&
   308→      timingPrecision.clockResolution <= 100 &&
   309→      timingPrecision.jitter < 0.5 &&
   310→      fpsMetrics.frameTimeVariance < 1;
   311→    
   312→    const canRun5msPrecision = 
   313→      capabilities.audioContextSupported &&
   314→      (capabilities.webGL2Supported || capabilities.webGL1Supported) &&
   315→      timingPrecision.clockResolution <= 1000 &&
   316→      timingPrecision.jitter < 2;
   317→    
   318→    const canRun16msPrecision = true; // Always achievable with requestAnimationFrame
   319→    
   320→    // Determine recommended frame rate
   321→    let recommendedFrameRate = 60;
   322→    if (fpsMetrics.actualFps >= 144 && fpsMetrics.droppedFrames === 0) {
   323→      recommendedFrameRate = 144;
   324→    } else if (fpsMetrics.actualFps >= 120 && fpsMetrics.droppedFrames <= 2) {
   325→      recommendedFrameRate = 120;
   326→    }
   327→    
   328→    return {
   329→      canRun2msPrecision,
   330→      canRun5msPrecision,
   331→      canRun16msPrecision,
   332→      recommendedFrameRate,
   333→      warnings
   334→    };
   335→  }
   336→
   337→  /**
   338→   * Run complete hardware timing validation
   339→   */
   340→  async validate(options: {
   341→    testDuration?: number;
   342→    targetFps?: number;
   343→  } = {}): Promise<TimingValidationResult> {
   344→    const {
   345→      testDuration = 3000, // 3 seconds default
   346→      targetFps = 60
   347→    } = options;
   348→    
   349→    // Detect hardware capabilities
   350→    const deviceCapabilities = this.detectCapabilities();
   351→    
   352→    // Test frame rate stability
   353→    const fpsMetrics = await this.testFrameRateStability(targetFps, testDuration);
   354→    
   355→    // Test timing precision
   356→    const timingPrecision = await this.testTimingPrecision();
   357→    
   358→    // Get memory metrics
   359→    const memoryMetrics = this.getMemoryMetrics();
   360→    
   361→    // Determine compatibility
   362→    const compatibilityMatrix = this.determineCompatibility(
   363→      deviceCapabilities,
   364→      fpsMetrics,
   365→      timingPrecision
   366→    );
   367→    
   368→    return {
   369→      deviceCapabilities,
   370→      fpsMetrics: {
   371→        targetFps,
   372→        actualFps: fpsMetrics.actualFps,
   373→        fpsVariance: fpsMetrics.fpsVariance,
   374→        frameTimeVariance: fpsMetrics.frameTimeVariance,
   375→        droppedFrames: fpsMetrics.droppedFrames,
   376→        testDuration
   377→      },
   378→      memoryMetrics,
   379→      timingPrecision,
   380→      compatibilityMatrix
   381→    };
   382→  }
   383→
   384→  /**
   385→   * Generate human-readable report from validation results
   386→   */
   387→  generateReport(results: TimingValidationResult): string {
   388→    const { deviceCapabilities, fpsMetrics, timingPrecision, compatibilityMatrix } = results;
   389→    
   390→    let report = '# Hardware Timing Validation Report\n\n';
   391→    
   392→    report += '## Device Capabilities\n';
   393→    report += `- Platform: ${deviceCapabilities.platform}\n`;
   394→    report += `- WebGL2: ${deviceCapabilities.webGL2Supported ? '✓' : '✗'}\n`;
   395→    report += `- WebGL1: ${deviceCapabilities.webGL1Supported ? '✓' : '✗'}\n`;
   396→    report += `- Audio Context: ${deviceCapabilities.audioContextSupported ? '✓' : '✗'}\n`;
   397→    report += `- CPU Cores: ${deviceCapabilities.hardwareConcurrency}\n`;
   398→    if (deviceCapabilities.deviceMemory) {
   399→      report += `- Device Memory: ${deviceCapabilities.deviceMemory}GB\n`;
   400→    }
   401→    report += `- Performance.now() Resolution: ${deviceCapabilities.performanceNowResolution.toFixed(3)}ms\n\n`;
   402→    
   403→    report += '## Frame Rate Performance\n';
   404→    report += `- Target FPS: ${fpsMetrics.targetFps}\n`;
   405→    report += `- Actual FPS: ${fpsMetrics.actualFps.toFixed(1)}\n`;
   406→    report += `- FPS Variance: ${fpsMetrics.fpsVariance.toFixed(2)}\n`;
   407→    report += `- Frame Time Variance: ${fpsMetrics.frameTimeVariance.toFixed(2)}ms\n`;
   408→    report += `- Dropped Frames: ${fpsMetrics.droppedFrames}\n\n`;
   409→    
   410→    report += '## Timing Precision\n';
   411→    report += `- Clock Resolution: ${timingPrecision.clockResolution.toFixed(0)}μs\n`;
   412→    report += `- Drift Rate: ${(timingPrecision.driftRate * 100).toFixed(3)}%\n`;
   413→    report += `- Timing Jitter: ${timingPrecision.jitter.toFixed(2)}ms\n`;
   414→    report += `- Max Deviation: ${timingPrecision.maxDeviation.toFixed(2)}ms\n\n`;
   415→    
   416→    report += '## Compatibility Assessment\n';
   417→    report += `- 2ms Precision: ${compatibilityMatrix.canRun2msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
   418→    report += `- 5ms Precision: ${compatibilityMatrix.canRun5msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
   419→    report += `- 16ms Precision: ${compatibilityMatrix.canRun16msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
   420→    report += `- Recommended Frame Rate: ${compatibilityMatrix.recommendedFrameRate} FPS\n\n`;
   421→    
   422→    if (compatibilityMatrix.warnings.length > 0) {
   423→      report += '## Warnings\n';
   424→      compatibilityMatrix.warnings.forEach(warning => {
   425→        report += `- ⚠️ ${warning}\n`;
   426→      });
   427→    }
   428→    
   429→    return report;
   430→  }
   431→}

