import { PrecisionClock } from './PrecisionClock';
import { TimingDriftDetector } from './TimingDriftDetector';

/**
 * Hardware capabilities test results
 */
export interface HardwareCapabilities {
  webGL2Supported: boolean;
  webGL1Supported: boolean;
  canvasSupported: boolean;
  requestVideoFrameCallbackSupported: boolean;
  audioContextSupported: boolean;
  performanceNowResolution: number;
  displayRefreshRate: number;
  hardwareConcurrency: number;
  deviceMemory?: number;
  userAgent: string;
  platform: string;
}

/**
 * Timing validation results
 */
export interface TimingValidationResult {
  deviceCapabilities: HardwareCapabilities;
  fpsMetrics: {
    targetFps: number;
    actualFps: number;
    fpsVariance: number;
    frameTimeVariance: number;
    droppedFrames: number;
    testDuration: number;
  };
  memoryMetrics: {
    heapUsed: number;
    heapTotal: number;
    heapLimit: number;
    externalMemory: number;
  };
  timingPrecision: {
    clockResolution: number;
    driftRate: number;
    jitter: number;
    maxDeviation: number;
  };
  compatibilityMatrix: {
    canRun2msPrecision: boolean;
    canRun5msPrecision: boolean;
    canRun16msPrecision: boolean;
    recommendedFrameRate: number;
    warnings: string[];
  };
}

/**
 * Hardware timing validation suite for validating <2ms precision claims
 */
export class HardwareTimingValidator {
  private clock: PrecisionClock;
  private driftDetector: TimingDriftDetector;

  constructor() {
    this.clock = new PrecisionClock();
    this.driftDetector = new TimingDriftDetector();
  }

  /**
   * Detect hardware capabilities
   */
  private detectCapabilities(): HardwareCapabilities {
    const canvas = document.createElement('canvas');
    const gl2 = canvas.getContext('webgl2');
    const gl1 = !gl2 ? canvas.getContext('webgl') : null;

    // Measure performance.now() resolution
    const perfSamples: number[] = [];
    for (let i = 0; i < 1000; i++) {
      perfSamples.push(performance.now());
    }

    // Calculate minimum non-zero delta
    const deltas: number[] = [];
    for (let i = 1; i < perfSamples.length; i++) {
      const delta = perfSamples[i] - perfSamples[i - 1];
      if (delta > 0) deltas.push(delta);
    }

    const performanceNowResolution = deltas.length > 0 
      ? Math.min(...deltas)
      : 0.001; // Fallback to 1 microsecond

    return {
      webGL2Supported: !!gl2,
      webGL1Supported: !!gl1 || !!gl2,
      canvasSupported: !!canvas.getContext('2d'),
      requestVideoFrameCallbackSupported: 'requestVideoFrameCallback' in HTMLVideoElement.prototype,
      audioContextSupported: typeof AudioContext !== 'undefined',
      performanceNowResolution,
      displayRefreshRate: screen.height && 'refreshRate' in screen ? (screen as any).refreshRate : 60,
      hardwareConcurrency: navigator.hardwareConcurrency || 1,
      deviceMemory: (navigator as any).deviceMemory,
      userAgent: navigator.userAgent,
      platform: navigator.platform
    };
  }

  /**
   * Test FPS stability and frame timing
   */
  private async testFrameRateStability(targetFps: number, durationMs: number): Promise<{
    actualFps: number;
    fpsVariance: number;
    frameTimeVariance: number;
    droppedFrames: number;
  }> {
    const frameTimes: number[] = [];
    const targetFrameTime = 1000 / targetFps;
    let lastTime = performance.now();
    let frameCount = 0;
    let droppedFrames = 0;

    return new Promise((resolve) => {
      const startTime = performance.now();

      const frame = () => {
        const currentTime = performance.now();
        const deltaTime = currentTime - lastTime;

        frameTimes.push(deltaTime);

        // Check for dropped frames (frame time > 1.5x target)
        if (deltaTime > targetFrameTime * 1.5) {
          droppedFrames++;
        }

        lastTime = currentTime;
        frameCount++;

        if (currentTime - startTime < durationMs) {
          requestAnimationFrame(frame);
        } else {
          // Calculate metrics
          const actualFps = frameCount / ((currentTime - startTime) / 1000);

          // Calculate variance
          const avgFrameTime = frameTimes.reduce((a, b) => a + b, 0) / frameTimes.length;
          const frameTimeVariance = Math.sqrt(
            frameTimes.reduce((sum, time) => sum + Math.pow(time - avgFrameTime, 2), 0) / frameTimes.length
          );

          const fpsValues = frameTimes.map(t => 1000 / t);
          const avgFps = fpsValues.reduce((a, b) => a + b, 0) / fpsValues.length;
          const fpsVariance = Math.sqrt(
            fpsValues.reduce((sum, fps) => sum + Math.pow(fps - avgFps, 2), 0) / fpsValues.length
          );

          resolve({
            actualFps,
            fpsVariance,
            frameTimeVariance,
            droppedFrames
          });
        }
      };

      requestAnimationFrame(frame);
    });
  }

  /**
   * Test memory usage patterns
   */
  private getMemoryMetrics(): {
    heapUsed: number;
    heapTotal: number;
    heapLimit: number;
    externalMemory: number;
  } {
    if ('memory' in performance && (performance as any).memory) {
      const memory = (performance as any).memory;
      return {
        heapUsed: memory.usedJSHeapSize || 0,
        heapTotal: memory.totalJSHeapSize || 0,
        heapLimit: memory.jsHeapSizeLimit || 0,
        externalMemory: 0 // Not available in browser
      };
    }

    // Fallback for browsers without memory API
    return {
      heapUsed: 0,
      heapTotal: 0,
      heapLimit: 0,
      externalMemory: 0
    };
  }

  /**
   * Test timing precision using PrecisionClock
   */
  private async testTimingPrecision(): Promise<{
    clockResolution: number;
    driftRate: number;
    jitter: number;
    maxDeviation: number;
  }> {
    await this.clock.initialize();

    // Test clock resolution
    const timestamps: number[] = [];
    for (let i = 0; i < 1000; i++) {
      timestamps.push(this.clock.now().monotonic);
    }

    // Calculate minimum non-zero delta for resolution
    const deltas: number[] = [];
    for (let i = 1; i < timestamps.length; i++) {
      const delta = timestamps[i] - timestamps[i - 1];
      if (delta > 0) deltas.push(delta);
    }

    const clockResolution = deltas.length > 0 
      ? Math.min(...deltas) * 1000 // Convert to microseconds
      : 1; // 1 microsecond fallback

    // Test drift over 5 seconds
    const driftStartTime = this.clock.now();
    const perfStartTime = performance.now();

    await new Promise(resolve => setTimeout(resolve, 5000));

    const driftEndTime = this.clock.now();
    const perfEndTime = performance.now();

    const clockElapsed = driftEndTime.monotonic - driftStartTime.monotonic;
    const perfElapsed = (perfEndTime - perfStartTime) / 1000;
    const driftRate = Math.abs(clockElapsed - perfElapsed) / perfElapsed;

    // Test jitter by measuring timing intervals
    const intervalDeltas: number[] = [];
    let lastInterval = this.clock.now().monotonic;

    for (let i = 0; i < 100; i++) {
      await new Promise(resolve => setTimeout(resolve, 10));
      const current = this.clock.now().monotonic;
      intervalDeltas.push((current - lastInterval) * 1000 - 10); // Expected 10ms, convert to ms
      lastInterval = current;
    }

    const avgDelta = intervalDeltas.reduce((a, b) => a + b, 0) / intervalDeltas.length;
    const jitter = Math.sqrt(
      intervalDeltas.reduce((sum, delta) => sum + Math.pow(delta - avgDelta, 2), 0) / intervalDeltas.length
    );

    const maxDeviation = Math.max(...intervalDeltas.map(d => Math.abs(d)));

    return {
      clockResolution,
      driftRate,
      jitter,
      maxDeviation
    };
  }

  /**
   * Determine compatibility based on test results
   */
  private determineCompatibility(
    capabilities: HardwareCapabilities,
    fpsMetrics: any,
    timingPrecision: any
  ): {
    canRun2msPrecision: boolean;
    canRun5msPrecision: boolean;
    canRun16msPrecision: boolean;
    recommendedFrameRate: number;
    warnings: string[];
  } {
    const warnings: string[] = [];

    // Check WebGL support
    if (!capabilities.webGL2Supported && !capabilities.webGL1Supported) {
      warnings.push('No WebGL support detected - performance will be limited');
    }

    // Check frame rate stability
    if (fpsMetrics.droppedFrames > 5) {
      warnings.push(`High dropped frame count (${fpsMetrics.droppedFrames}) - may impact timing precision`);
    }

    if (fpsMetrics.frameTimeVariance > 2) {
      warnings.push(`High frame time variance (${fpsMetrics.frameTimeVariance.toFixed(2)}ms) - timing may be unstable`);
    }

    // Check timing precision
    if (timingPrecision.clockResolution > 100) {
      warnings.push(`Low clock resolution (${timingPrecision.clockResolution.toFixed(0)}μs) - may limit precision`);
    }

    if (timingPrecision.jitter > 1) {
      warnings.push(`High timing jitter (${timingPrecision.jitter.toFixed(2)}ms) - precision degraded`);
    }

    // Determine precision capabilities
    const canRun2msPrecision = 
      capabilities.audioContextSupported &&
      capabilities.webGL2Supported &&
      timingPrecision.clockResolution <= 100 &&
      timingPrecision.jitter < 0.5 &&
      fpsMetrics.frameTimeVariance < 1;

    const canRun5msPrecision = 
      capabilities.audioContextSupported &&
      (capabilities.webGL2Supported || capabilities.webGL1Supported) &&
      timingPrecision.clockResolution <= 1000 &&
      timingPrecision.jitter < 2;

    const canRun16msPrecision = true; // Always achievable with requestAnimationFrame

    // Determine recommended frame rate
    let recommendedFrameRate = 60;
    if (fpsMetrics.actualFps >= 144 && fpsMetrics.droppedFrames === 0) {
      recommendedFrameRate = 144;
    } else if (fpsMetrics.actualFps >= 120 && fpsMetrics.droppedFrames <= 2) {
      recommendedFrameRate = 120;
    }

    return {
      canRun2msPrecision,
      canRun5msPrecision,
      canRun16msPrecision,
      recommendedFrameRate,
      warnings
    };
  }

  /**
   * Run complete hardware timing validation
   */
  async validate(options: {
    testDuration?: number;
    targetFps?: number;
  } = {}): Promise<TimingValidationResult> {
    const {
      testDuration = 3000, // 3 seconds default
      targetFps = 60
    } = options;

    // Detect hardware capabilities
    const deviceCapabilities = this.detectCapabilities();

    // Test frame rate stability
    const fpsMetrics = await this.testFrameRateStability(targetFps, testDuration);

    // Test timing precision
    const timingPrecision = await this.testTimingPrecision();

    // Get memory metrics
    const memoryMetrics = this.getMemoryMetrics();

    // Determine compatibility
    const compatibilityMatrix = this.determineCompatibility(
      deviceCapabilities,
      fpsMetrics,
      timingPrecision
    );

    return {
      deviceCapabilities,
      fpsMetrics: {
        targetFps,
        actualFps: fpsMetrics.actualFps,
        fpsVariance: fpsMetrics.fpsVariance,
        frameTimeVariance: fpsMetrics.frameTimeVariance,
        droppedFrames: fpsMetrics.droppedFrames,
        testDuration
      },
      memoryMetrics,
      timingPrecision,
      compatibilityMatrix
    };
  }

  /**
   * Generate human-readable report from validation results
   */
  generateReport(results: TimingValidationResult): string {
    const { deviceCapabilities, fpsMetrics, timingPrecision, compatibilityMatrix } = results;

    let report = '# Hardware Timing Validation Report\n\n';

    report += '## Device Capabilities\n';
    report += `- Platform: ${deviceCapabilities.platform}\n`;
    report += `- WebGL2: ${deviceCapabilities.webGL2Supported ? '✓' : '✗'}\n`;
    report += `- WebGL1: ${deviceCapabilities.webGL1Supported ? '✓' : '✗'}\n`;
    report += `- Audio Context: ${deviceCapabilities.audioContextSupported ? '✓' : '✗'}\n`;
    report += `- CPU Cores: ${deviceCapabilities.hardwareConcurrency}\n`;
    if (deviceCapabilities.deviceMemory) {
      report += `- Device Memory: ${deviceCapabilities.deviceMemory}GB\n`;
    }
    report += `- Performance.now() Resolution: ${deviceCapabilities.performanceNowResolution.toFixed(3)}ms\n\n`;

    report += '## Frame Rate Performance\n';
    report += `- Target FPS: ${fpsMetrics.targetFps}\n`;
    report += `- Actual FPS: ${fpsMetrics.actualFps.toFixed(1)}\n`;
    report += `- FPS Variance: ${fpsMetrics.fpsVariance.toFixed(2)}\n`;
    report += `- Frame Time Variance: ${fpsMetrics.frameTimeVariance.toFixed(2)}ms\n`;
    report += `- Dropped Frames: ${fpsMetrics.droppedFrames}\n\n`;

    report += '## Timing Precision\n';
    report += `- Clock Resolution: ${timingPrecision.clockResolution.toFixed(0)}μs\n`;
    report += `- Drift Rate: ${(timingPrecision.driftRate * 100).toFixed(3)}%\n`;
    report += `- Timing Jitter: ${timingPrecision.jitter.toFixed(2)}ms\n`;
    report += `- Max Deviation: ${timingPrecision.maxDeviation.toFixed(2)}ms\n\n`;

    report += '## Compatibility Assessment\n';
    report += `- 2ms Precision: ${compatibilityMatrix.canRun2msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- 5ms Precision: ${compatibilityMatrix.canRun5msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- 16ms Precision: ${compatibilityMatrix.canRun16msPrecision ? '✓ Supported' : '✗ Not Supported'}\n`;
    report += `- Recommended Frame Rate: ${compatibilityMatrix.recommendedFrameRate} FPS\n\n`;

    if (compatibilityMatrix.warnings.length > 0) {
      report += '## Warnings\n';
      compatibilityMatrix.warnings.forEach(warning => {
        report += `- ⚠️ ${warning}\n`;
      });
    }

    return report;
  }
}

