#!/usr/bin/env node

/**
 * CLI tool for hardware timing validation
 * Usage: npx @psyforge/timing validate-timing [options]
 */

import { HardwareTimingValidator } from '../HardwareTimingValidator';
import { writeFileSync } from 'fs';
import { resolve } from 'path';

interface CLIOptions {
  duration: number;
  targetFps: number;
  output?: string;
  json?: boolean;
  ci?: boolean;
}

function parseArgs(): CLIOptions {
  const args = process.argv.slice(2);
  const options: CLIOptions = {
    duration: 3000,
    targetFps: 60
  };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--duration':
      case '-d':
        options.duration = parseInt(args[++i], 10);
        break;
      case '--fps':
      case '-f':
        options.targetFps = parseInt(args[++i], 10);
        break;
      case '--output':
      case '-o':
        options.output = args[++i];
        break;
      case '--json':
        options.json = true;
        break;
      case '--ci':
        options.ci = true;
        break;
      case '--help':
      case '-h':
        showHelp();
        process.exit(0);
    }
  }

  return options;
}

function showHelp() {
  console.log(`
Hardware Timing Validation Tool

Usage: npx @psyforge/timing validate-timing [options]

Options:
  -d, --duration <ms>    Test duration in milliseconds (default: 3000)
  -f, --fps <fps>        Target frame rate for testing (default: 60)
  -o, --output <file>    Output results to file
  --json                 Output results as JSON
  --ci                   CI mode - exit with error if requirements not met
  -h, --help            Show this help message

Examples:
  # Basic validation
  npx @psyforge/timing validate-timing

  # Test 144Hz display
  npx @psyforge/timing validate-timing --fps 144

  # CI integration
  npx @psyforge/timing validate-timing --ci --json --output timing-report.json
`);
}

async function runValidation(options: CLIOptions) {
  console.log('🔬 Starting hardware timing validation...\n');
  console.log(`Configuration:`);
  console.log(`  Test Duration: ${options.duration}ms`);
  console.log(`  Target FPS: ${options.targetFps}`);
  console.log('');

  const validator = new HardwareTimingValidator();

  try {
    const results = await validator.validate({
      testDuration: options.duration,
      targetFps: options.targetFps
    });

    if (options.json) {
      const jsonOutput = JSON.stringify(results, null, 2);

      if (options.output) {
        writeFileSync(resolve(options.output), jsonOutput);
        console.log(`✅ Results saved to ${options.output}`);
      } else {
        console.log(jsonOutput);
      }
    } else {
      // Generate human-readable report
      const report = validator.generateReport(results);
      console.log(report);

      if (options.output) {
        writeFileSync(resolve(options.output), report);
        console.log(`\n✅ Report saved to ${options.output}`);
      }
    }

    // CI mode: check if minimum requirements are met
    if (options.ci) {
      const meetsRequirements = checkCIRequirements(results);

      if (!meetsRequirements) {
        console.error('\n❌ Hardware timing requirements not met!');
        process.exit(1);
      } else {
        console.log('\n✅ Hardware timing requirements met!');
      }
    }

    // Display summary
    if (!options.json) {
      console.log('\n📊 Summary:');
      console.log(`  ✓ 2ms Precision: ${results.compatibilityMatrix.canRun2msPrecision ? '✅ Supported' : '❌ Not Supported'}`);
      console.log(`  ✓ 5ms Precision: ${results.compatibilityMatrix.canRun5msPrecision ? '✅ Supported' : '❌ Not Supported'}`);
      console.log(`  ✓ Recommended FPS: ${results.compatibilityMatrix.recommendedFrameRate}`);

      if (results.compatibilityMatrix.warnings.length > 0) {
        console.log('\n⚠️  Warnings:');
        results.compatibilityMatrix.warnings.forEach(warning => {
          console.log(`  - ${warning}`);
        });
      }
    }

  } catch (error) {
    console.error('❌ Validation failed:', error);
    process.exit(1);
  }
}

function checkCIRequirements(results: any): boolean {
  // Minimum requirements for CI:
  // - Must support at least 5ms precision
  // - Less than 10 dropped frames
  // - Timing jitter < 5ms
  // - Frame time variance < 5ms

  return results.compatibilityMatrix.canRun5msPrecision &&
         results.fpsMetrics.droppedFrames < 10 &&
         results.timingPrecision.jitter < 5 &&
         results.fpsMetrics.frameTimeVariance < 5;
}

// Run the validation
const options = parseArgs();
runValidation(options).catch(error => {
  console.error('Fatal error:', error);
  process.exit(1);
});

