#!/usr/bin/env node

/**
 * CI script for running hardware timing validation using Puppeteer
 * This script launches a headless browser to run timing validation tests
 */

const puppeteer = require('puppeteer');
const { resolve } = require('path');
const { existsSync, writeFileSync } = require('fs');

async function runCIValidation(options = {}) {
  const {
    duration = 3000,
    targetFps = 60,
    outputFile = null,
    failOn2ms = false,
    failOn5ms = false,
    headless = true
  } = options;

  console.log('🚀 Starting CI Timing Validation');
  console.log(`   Duration: ${duration}ms`);
  console.log(`   Target FPS: ${targetFps}`);
  console.log(`   Headless: ${headless}`);
  console.log('');

  let browser;
  let exitCode = 0;

  try {
    // Launch browser
    browser = await puppeteer.launch({
      headless,
      args: [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-dev-shm-usage',
        '--disable-web-security',
        '--enable-precise-memory-info',
        '--use-angle=swiftshader', // Use software rendering for consistency
      ]
    });

    const page = await browser.newPage();

    // Enable console logging
    page.on('console', msg => {
      console.log('Browser:', msg.text());
    });

    page.on('error', err => {
      console.error('Browser error:', err);
    });

    // Set viewport for consistent rendering
    await page.setViewport({
      width: 1920,
      height: 1080
    });

    // Build URL with parameters
    const htmlPath = resolve(__dirname, '../src/browser-runner/timing-validation-runner.html');
    if (!existsSync(htmlPath)) {
      throw new Error(`HTML runner not found at ${htmlPath}`);
    }

    const url = `file://${htmlPath}?duration=${duration}&fps=${targetFps}&autorun=true`;

    console.log('📄 Loading validation page...');
    await page.goto(url, { waitUntil: 'networkidle0' });

    // Wait for validation to complete
    console.log('⏳ Running validation tests...\n');

    const result = await page.waitForEvent('validationComplete', 'validationError', {
      timeout: duration + 30000 // Add 30 seconds buffer
    });

    if (result.type === 'validationError') {
      const error = result.detail.error;
      console.error('❌ Validation failed:', error.message);
      exitCode = 1;
    } else {
      // Get results from page
      const results = await page.evaluate(() => window.validationResults);
      const report = await page.evaluate(() => window.validationReport);

      // Display key metrics
      console.log('📊 Validation Results:');
      console.log(`   Platform: ${results.deviceCapabilities.platform}`);
      console.log(`   WebGL: ${results.deviceCapabilities.webGL2Supported ? 'WebGL2' : 
                               results.deviceCapabilities.webGL1Supported ? 'WebGL1' : 'None'}`);
      console.log(`   Actual FPS: ${results.fpsMetrics.actualFps.toFixed(1)}`);
      console.log(`   Clock Resolution: ${results.timingPrecision.clockResolution.toFixed(0)}μs`);
      console.log(`   2ms Precision: ${results.compatibilityMatrix.canRun2msPrecision ? '✅' : '❌'}`);
      console.log(`   5ms Precision: ${results.compatibilityMatrix.canRun5msPrecision ? '✅' : '❌'}`);
      console.log('');

      // Display warnings
      if (results.compatibilityMatrix.warnings.length > 0) {
        console.log('⚠️  Warnings:');
        results.compatibilityMatrix.warnings.forEach(warning => {
          console.log(`   - ${warning}`);
        });
        console.log('');
      }

      // Save output file if requested
      if (outputFile) {
        const output = {
          timestamp: new Date().toISOString(),
          results,
          report
        };
        writeFileSync(outputFile, JSON.stringify(output, null, 2));
        console.log(`💾 Results saved to ${outputFile}\n`);
      }

      // Check CI requirements
      if (failOn2ms && !results.compatibilityMatrix.canRun2msPrecision) {
        console.error('❌ CI FAILED: 2ms precision requirement not met');
        exitCode = 1;
      }

      if (failOn5ms && !results.compatibilityMatrix.canRun5msPrecision) {
        console.error('❌ CI FAILED: 5ms precision requirement not met');
        exitCode = 1;
      }

      // Additional CI checks
      if (results.fpsMetrics.droppedFrames > 10) {
        console.error(`❌ CI WARNING: High dropped frame count (${results.fpsMetrics.droppedFrames})`);
      }

      if (results.timingPrecision.jitter > 5) {
        console.error(`❌ CI WARNING: High timing jitter (${results.timingPrecision.jitter.toFixed(2)}ms)`);
      }
    }

  } catch (error) {
    console.error('❌ CI validation error:', error);
    exitCode = 1;
  } finally {
    if (browser) {
      await browser.close();
    }
  }

  if (exitCode === 0) {
    console.log('✅ CI timing validation passed!');
  } else {
    console.log('❌ CI timing validation failed!');
  }

  process.exit(exitCode);
}

// Helper to wait for page events
async function waitForEvent(page, successEvent, errorEvent, options = {}) {
  return new Promise((resolve, reject) => {
    const timeout = setTimeout(() => {
      reject(new Error('Validation timeout'));
    }, options.timeout || 60000);

    page.evaluateOnNewDocument((successEvent, errorEvent) => {
      window.addEventListener(successEvent, (e) => {
        window.__validationResult = { type: successEvent, detail: e.detail };
      });
      window.addEventListener(errorEvent, (e) => {
        window.__validationResult = { type: errorEvent, detail: e.detail };
      });
    }, successEvent, errorEvent);

    const checkResult = setInterval(async () => {
      try {
        const result = await page.evaluate(() => window.__validationResult);
        if (result) {
          clearInterval(checkResult);
          clearTimeout(timeout);
          resolve(result);
        }
      } catch (e) {
        // Page might be navigating
      }
    }, 100);
  });
}

// Add helper to page
puppeteer.Page.prototype.waitForEvent = waitForEvent;

// Parse command line arguments
const args = process.argv.slice(2);
const options = {};

for (let i = 0; i < args.length; i++) {
  switch (args[i]) {
    case '--duration':
      options.duration = parseInt(args[++i], 10);
      break;
    case '--fps':
      options.targetFps = parseInt(args[++i], 10);
      break;
    case '--output':
      options.outputFile = args[++i];
      break;
    case '--fail-on-2ms':
      options.failOn2ms = true;
      break;
    case '--fail-on-5ms':
      options.failOn5ms = true;
      break;
    case '--no-headless':
      options.headless = false;
      break;
    case '--help':
      console.log(`
CI Timing Validation Script

Usage: node ci-timing-validation.js [options]

Options:
  --duration <ms>     Test duration (default: 3000)
  --fps <fps>         Target frame rate (default: 60)
  --output <file>     Save results to JSON file
  --fail-on-2ms       Fail CI if 2ms precision not supported
  --fail-on-5ms       Fail CI if 5ms precision not supported
  --no-headless       Run browser in visible mode
  --help              Show this help

Examples:
  node ci-timing-validation.js --fail-on-5ms
  node ci-timing-validation.js --duration 5000 --output results.json
`);
      process.exit(0);
  }
}

// Run validation
runCIValidation(options).catch(error => {
  console.error('Fatal error:', error);
  process.exit(1);
});

