#!/usr/bin/env node

/**
 * CI script for running hardware timing validation using Playwright
 * Supports multiple browsers (chromium, firefox, webkit)
 */

const { chromium, firefox, webkit } = require('playwright');
const { resolve } = require('path');
const { existsSync, writeFileSync } = require('fs');

async function runCIValidation(options = {}) {
  const {
    browser: browserType = 'chromium',
    duration = 3000,
    targetFps = 60,
    outputFile = null,
    failOn2ms = false,
    failOn5ms = false,
    headless = true
  } = options;

  console.log('🚀 Starting CI Timing Validation with Playwright');
  console.log(`   Browser: ${browserType}`);
  console.log(`   Duration: ${duration}ms`);
  console.log(`   Target FPS: ${targetFps}`);
  console.log(`   Headless: ${headless}`);
  console.log('');

  let browser;
  let exitCode = 0;

  try {
    // Select browser engine
    const browserEngine = {
      chromium,
      firefox,
      webkit
    }[browserType];

    if (!browserEngine) {
      throw new Error(`Unknown browser type: ${browserType}`);
    }

    // Launch browser with appropriate options
    const launchOptions = {
      headless,
      args: []
    };

    // Browser-specific options
    if (browserType === 'chromium') {
      launchOptions.args = [
        '--no-sandbox',
        '--disable-setuid-sandbox',
        '--disable-dev-shm-usage',
        '--enable-precise-memory-info',
        '--use-angle=swiftshader', // Software rendering for consistency
      ];
    }

    browser = await browserEngine.launch(launchOptions);
    const context = await browser.newContext({
      viewport: { width: 1920, height: 1080 }
    });
    const page = await context.newPage();

    // Enable console logging
    page.on('console', msg => {
      const type = msg.type();
      const text = msg.text();
      if (type === 'error') {
        console.error('Browser error:', text);
      } else {
        console.log(`Browser [${type}]:`, text);
      }
    });

    page.on('pageerror', err => {
      console.error('Page error:', err);
    });

    // Build URL with parameters
    const htmlPath = resolve(__dirname, '../src/browser-runner/timing-validation-runner.html');
    if (!existsSync(htmlPath)) {
      throw new Error(`HTML runner not found at ${htmlPath}`);
    }

    const url = `file://${htmlPath}?duration=${duration}&fps=${targetFps}&autorun=true`;

    console.log('📄 Loading validation page...');
    await page.goto(url, { waitUntil: 'networkidle' });

    // Wait for validation to complete
    console.log('⏳ Running validation tests...\n');

    const result = await Promise.race([
      page.waitForFunction(() => window.validationResults || window.validationError, {
        timeout: duration + 30000
      }),
      page.waitForTimeout(duration + 30000).then(() => {
        throw new Error('Validation timeout');
      })
    ]);

    // Get results from page
    const validationData = await page.evaluate(() => ({
      results: window.validationResults,
      error: window.validationError,
      report: window.validationReport
    }));

    if (validationData.error) {
      console.error('❌ Validation failed:', validationData.error.message);
      exitCode = 1;
    } else if (validationData.results) {
      const results = validationData.results;
      const report = validationData.report;

      // Display key metrics
      console.log('📊 Validation Results:');
      console.log(`   Browser: ${browserType}`);
      console.log(`   Platform: ${results.deviceCapabilities.platform}`);
      console.log(`   User Agent: ${results.deviceCapabilities.userAgent}`);
      console.log(`   WebGL: ${results.deviceCapabilities.webGL2Supported ? 'WebGL2' : 
                               results.deviceCapabilities.webGL1Supported ? 'WebGL1' : 'None'}`);
      console.log(`   Hardware Concurrency: ${results.deviceCapabilities.hardwareConcurrency}`);
      console.log(`   Actual FPS: ${results.fpsMetrics.actualFps.toFixed(1)} (target: ${results.fpsMetrics.targetFps})`);
      console.log(`   FPS Variance: ${results.fpsMetrics.fpsVariance.toFixed(2)}`);
      console.log(`   Frame Time Variance: ${results.fpsMetrics.frameTimeVariance.toFixed(2)}ms`);
      console.log(`   Dropped Frames: ${results.fpsMetrics.droppedFrames}`);
      console.log(`   Clock Resolution: ${results.timingPrecision.clockResolution.toFixed(0)}μs`);
      console.log(`   Timing Jitter: ${results.timingPrecision.jitter.toFixed(2)}ms`);
      console.log(`   Drift Rate: ${(results.timingPrecision.driftRate * 100).toFixed(3)}%`);
      console.log(`   2ms Precision: ${results.compatibilityMatrix.canRun2msPrecision ? '✅ Supported' : '❌ Not Supported'}`);
      console.log(`   5ms Precision: ${results.compatibilityMatrix.canRun5msPrecision ? '✅ Supported' : '❌ Not Supported'}`);
      console.log(`   Recommended FPS: ${results.compatibilityMatrix.recommendedFrameRate}`);
      console.log('');

      // Display warnings
      if (results.compatibilityMatrix.warnings.length > 0) {
        console.log('⚠️  Warnings:');
        results.compatibilityMatrix.warnings.forEach(warning => {
          console.log(`   - ${warning}`);
        });
        console.log('');
      }

      // Save output file if requested
      if (outputFile) {
        const output = {
          timestamp: new Date().toISOString(),
          browser: browserType,
          platform: process.platform,
          nodeVersion: process.version,
          results,
          report
        };
        writeFileSync(outputFile, JSON.stringify(output, null, 2));
        console.log(`💾 Results saved to ${outputFile}\n`);
      }

      // Check CI requirements
      if (failOn2ms && !results.compatibilityMatrix.canRun2msPrecision) {
        console.error('❌ CI FAILED: 2ms precision requirement not met');
        exitCode = 1;
      }

      if (failOn5ms && !results.compatibilityMatrix.canRun5msPrecision) {
        console.error('❌ CI FAILED: 5ms precision requirement not met');
        exitCode = 1;
      }

      // Additional CI checks
      if (results.fpsMetrics.droppedFrames > 10) {
        console.warn(`⚠️  CI WARNING: High dropped frame count (${results.fpsMetrics.droppedFrames})`);
      }

      if (results.timingPrecision.jitter > 5) {
        console.warn(`⚠️  CI WARNING: High timing jitter (${results.timingPrecision.jitter.toFixed(2)}ms)`);
      }

