        console.warn(`⚠️  CI WARNING: High frame time variance (${results.fpsMetrics.frameTimeVariance.toFixed(2)}ms)`);
      }

      // Performance regression checks
      if (results.timingPrecision.clockResolution > 1000) {
        console.warn(`⚠️  CI WARNING: Low clock resolution (${results.timingPrecision.clockResolution.toFixed(0)}μs)`);
      }

    } else {
      console.error('❌ No validation results found');
      exitCode = 1;
    }

  } catch (error) {
    console.error('❌ CI validation error:', error);
    exitCode = 1;
  } finally {
    if (browser) {
      await browser.close();
    }
  }

  if (exitCode === 0) {
    console.log('✅ CI timing validation passed!');
  } else {
    console.log('❌ CI timing validation failed!');
  }

  process.exit(exitCode);
}

// Parse command line arguments
const args = process.argv.slice(2);
const options = {};

for (let i = 0; i < args.length; i++) {
  switch (args[i]) {
