/**
 * Canvas2D Fallback Renderer
 * Provides basic rendering capabilities when WebGL is not available
 */

import type { TimelineContext } from '../../core/Timeline.js';

export interface Canvas2DStimulus {
  id: string;
  type: 'text' | 'image' | 'shape';
  x: number;
  y: number;
  width?: number;
  height?: number;
  rotation?: number;
  alpha?: number;
  visible?: boolean;
  data: any;
}

export class Canvas2DFallbackRenderer {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private stimuli: Map<string, Canvas2DStimulus> = new Map();
  private backgroundColor: string = '#000000';
  private animationFrameId: number | null = null;
  private isRunning: boolean = false;

  constructor(canvas?: HTMLCanvasElement) {
    this.canvas = canvas || document.createElement('canvas');
    const ctx = this.canvas.getContext('2d');

    if (!ctx) {
      throw new Error('Canvas 2D context not available');
    }

    this.ctx = ctx;
    this.setupCanvas();
  }

  private setupCanvas(): void {
    if (!this.canvas.parentElement) {
      this.canvas.id = 'psyforge-canvas2d-fallback';
      this.canvas.style.position = 'fixed';
      this.canvas.style.top = '0';
      this.canvas.style.left = '0';
      this.canvas.style.width = '100%';
      this.canvas.style.height = '100%';
      this.canvas.style.zIndex = '1000';
      document.body.appendChild(this.canvas);
    }

    this.resize();
    window.addEventListener('resize', () => this.resize());
  }

  private resize(): void {
    const dpr = window.devicePixelRatio || 1;
    this.canvas.width = window.innerWidth * dpr;
    this.canvas.height = window.innerHeight * dpr;
    this.ctx.scale(dpr, dpr);
    this.canvas.style.width = window.innerWidth + 'px';
    this.canvas.style.height = window.innerHeight + 'px';
  }

  /**
   * Start the rendering loop
   */
  start(): void {
    if (this.isRunning) return;

    this.isRunning = true;
    this.render();
  }

  /**
   * Stop the rendering loop
   */
  stop(): void {
    this.isRunning = false;
    if (this.animationFrameId !== null) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }
  }

  /**
   * Main render loop
   */
  private render = (): void => {
    if (!this.isRunning) return;

    // Clear canvas
    this.ctx.fillStyle = this.backgroundColor;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Render all stimuli
    const sortedStimuli = Array.from(this.stimuli.values()).sort((a, b) => {
      // Sort by z-index if available, otherwise by insertion order
      return 0;
    });

    for (const stimulus of sortedStimuli) {
      if (!stimulus.visible) continue;

      this.ctx.save();

      // Apply transformations
      this.ctx.globalAlpha = stimulus.alpha ?? 1;
      this.ctx.translate(stimulus.x, stimulus.y);

      if (stimulus.rotation) {
        this.ctx.rotate(stimulus.rotation);
      }

      // Render based on type
      switch (stimulus.type) {
        case 'text':
          this.renderText(stimulus);
          break;
        case 'image':
          this.renderImage(stimulus);
          break;
        case 'shape':
          this.renderShape(stimulus);
          break;
      }

      this.ctx.restore();
    }

    this.animationFrameId = requestAnimationFrame(this.render);
  };

  private renderText(stimulus: Canvas2DStimulus): void {
    const data = stimulus.data;

    this.ctx.font = `${data.fontSize || 24}px ${data.fontFamily || 'Arial'}`;
    this.ctx.fillStyle = data.color || '#FFFFFF';
    this.ctx.textAlign = data.align || 'center';
    this.ctx.textBaseline = data.baseline || 'middle';

    if (data.shadow) {
      this.ctx.shadowColor = data.shadow.color || 'rgba(0,0,0,0.5)';
      this.ctx.shadowBlur = data.shadow.blur || 4;
      this.ctx.shadowOffsetX = data.shadow.offsetX || 2;
      this.ctx.shadowOffsetY = data.shadow.offsetY || 2;
    }

    this.ctx.fillText(data.text, 0, 0);
  }

  private renderImage(stimulus: Canvas2DStimulus): void {
    const data = stimulus.data;

    if (data.image && data.image.complete) {
      const width = stimulus.width || data.image.width;
      const height = stimulus.height || data.image.height;

      this.ctx.drawImage(
        data.image,
        -width / 2,
        -height / 2,
        width,
        height
      );
    }
  }

  private renderShape(stimulus: Canvas2DStimulus): void {
    const data = stimulus.data;

    this.ctx.fillStyle = data.fillColor || '#FFFFFF';
    this.ctx.strokeStyle = data.strokeColor || '#000000';
    this.ctx.lineWidth = data.strokeWidth || 1;

    switch (data.shape) {
      case 'rectangle':
        const rectWidth = stimulus.width || 100;
        const rectHeight = stimulus.height || 100;

        if (data.fillColor) {
          this.ctx.fillRect(-rectWidth / 2, -rectHeight / 2, rectWidth, rectHeight);
        }
        if (data.strokeColor) {
          this.ctx.strokeRect(-rectWidth / 2, -rectHeight / 2, rectWidth, rectHeight);
        }
        break;

      case 'circle':
        const radius = (stimulus.width || 100) / 2;

        this.ctx.beginPath();
        this.ctx.arc(0, 0, radius, 0, Math.PI * 2);

        if (data.fillColor) {
          this.ctx.fill();
        }
        if (data.strokeColor) {
          this.ctx.stroke();
        }
        break;

      case 'polygon':
        if (data.points && data.points.length > 0) {
          this.ctx.beginPath();
          this.ctx.moveTo(data.points[0].x, data.points[0].y);

          for (let i = 1; i < data.points.length; i++) {
            this.ctx.lineTo(data.points[i].x, data.points[i].y);
          }

          this.ctx.closePath();

          if (data.fillColor) {
            this.ctx.fill();
          }
          if (data.strokeColor) {
            this.ctx.stroke();
          }
        }
        break;
    }
  }

  /**
   * Add a stimulus to the renderer
   */
  addStimulus(stimulus: Canvas2DStimulus): void {
    this.stimuli.set(stimulus.id, stimulus);
  }

  /**
   * Update a stimulus
   */
  updateStimulus(id: string, updates: Partial<Canvas2DStimulus>): void {
    const stimulus = this.stimuli.get(id);
    if (stimulus) {
      Object.assign(stimulus, updates);
    }
  }

  /**
   * Remove a stimulus
   */
  removeStimulus(id: string): void {
    this.stimuli.delete(id);
  }

  /**
   * Clear all stimuli
   */
  clearStimuli(): void {
    this.stimuli.clear();
  }

  /**
   * Set background color
   */
  setBackgroundColor(color: string): void {
    this.backgroundColor = color;
  }

  /**
   * Take a screenshot
   */
  async takeScreenshot(): Promise<string> {
    return this.canvas.toDataURL('image/png');
  }

  /**
   * Get performance metrics
   */
  getPerformanceMetrics(): {
    stimulusCount: number;
    fps: number;
  } {
    return {
      stimulusCount: this.stimuli.size,
      fps: 0 // Canvas2D doesn't provide easy FPS tracking
    };
  }

  /**
   * Destroy the renderer
   */
  destroy(): void {
    this.stop();
    this.stimuli.clear();

    if (this.canvas.parentElement) {
      this.canvas.remove();
    }

    window.removeEventListener('resize', () => this.resize());
  }

  /**
   * Convert PIXI-like properties to Canvas2D stimulus
   */
  static pixiToCanvas2D(pixiObject: any): Canvas2DStimulus | null {
    const type = pixiObject.constructor.name;

    if (type === 'Text') {
      return {
        id: pixiObject.uid?.toString() || Math.random().toString(36),
        type: 'text',
        x: pixiObject.x,
        y: pixiObject.y,
        rotation: pixiObject.rotation,
        alpha: pixiObject.alpha,
        visible: pixiObject.visible,
        data: {
          text: pixiObject.text,
          fontSize: pixiObject.style?.fontSize,
          fontFamily: pixiObject.style?.fontFamily,
          color: pixiObject.style?.fill,
          align: pixiObject.style?.align
        }
      };
    } else if (type === 'Sprite') {
      return {
        id: pixiObject.uid?.toString() || Math.random().toString(36),
        type: 'image',
        x: pixiObject.x,
        y: pixiObject.y,
        width: pixiObject.width,
        height: pixiObject.height,
        rotation: pixiObject.rotation,
        alpha: pixiObject.alpha,
        visible: pixiObject.visible,
        data: {
          image: pixiObject.texture?.source?.resource
        }
      };
    } else if (type === 'Graphics') {
      // Simplified graphics to shape conversion
      return {
        id: pixiObject.uid?.toString() || Math.random().toString(36),
        type: 'shape',
        x: pixiObject.x,
        y: pixiObject.y,
        width: pixiObject.width,
        height: pixiObject.height,
        rotation: pixiObject.rotation,
        alpha: pixiObject.alpha,
        visible: pixiObject.visible,
        data: {
          shape: 'rectangle', // Default to rectangle
          fillColor: '#FFFFFF',
          strokeColor: '#000000'
        }
      };
    }

    return null;
  }
}

/**
 * Warning overlay for Canvas2D fallback mode
 */
export function showCanvas2DWarning(): void {
  const warning = document.createElement('div');
  warning.style.cssText = `
    position: fixed;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    background: #ff5722;
    color: white;
    padding: 15px 25px;
    border-radius: 4px;
    font-family: Arial, sans-serif;
    font-size: 14px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.3);
    z-index: 10001;
    text-align: center;
  `;

  warning.innerHTML = `
    <strong>⚠️ Performance Warning</strong><br>
    WebGL is not available. Using Canvas2D fallback mode.<br>
    Timing precision and visual effects are limited.
  `;

  document.body.appendChild(warning);

  // Remove after 15 seconds
  setTimeout(() => {
    warning.style.transition = 'opacity 0.5s';
    warning.style.opacity = '0';
    setTimeout(() => warning.remove(), 500);
  }, 15000);
}

