  warning.style.cssText = `
    position: fixed;
    bottom: 20px;
    left: 50%;
    transform: translateX(-50%);
    background: #ff5722;
    color: white;
    padding: 15px 25px;
    border-radius: 4px;
    font-family: Arial, sans-serif;
    font-size: 14px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.3);
    z-index: 10001;
    text-align: center;
  `;

  warning.innerHTML = `
    <strong>⚠️ Performance Warning</strong><br>
    WebGL is not available. Using Canvas2D fallback mode.<br>
    Timing precision and visual effects are limited.
  `;

