async initialize(options: RendererOptions = {}): Promise<void> {
  if (this.isInitialized) {
    return;
  }

  // Check if we should force Canvas2D
  if (options.forceCanvas2D) {
    this.renderingMode = RenderingMode.CANVAS2D;
  }

  // Show compatibility warnings if requested
  if (options.showCompatibilityWarnings !== false) {
    WebGLCompatibility.showCompatibilityWarning();
  }

  // Parse background color
  let bgColor = 0x000000;
  let bgColorString = '#000000';
  if (options.backgroundColor !== undefined) {
    if (typeof options.backgroundColor === 'string') {
      bgColor = parseInt(options.backgroundColor.replace('#', ''), 16);
      bgColorString = options.backgroundColor;
    } else {
      bgColor = options.backgroundColor;
      bgColorString = '#' + options.backgroundColor.toString(16).padStart(6, '0');
    }
  }

  // Initialize based on rendering mode
  if (this.renderingMode === RenderingMode.CANVAS2D) {
    // Use Canvas2D fallback
    this.canvas2DRenderer = new Canvas2DFallbackRenderer();
    this.canvas2DRenderer.setBackgroundColor(bgColorString);
    this.canvas2DRenderer.start();

    if (options.showCompatibilityWarnings !== false) {
      showCanvas2DWarning();
    }

    console.warn('Using Canvas2D fallback renderer - timing precision and effects limited');
  } else {
    // Use PIXI.js with WebGL
    try {
      // Get recommended settings based on capabilities
      const recommendedSettings = WebGLCompatibility.getRecommendedSettings();

      this.app = new PIXI.Application();

      await this.app.init({
        width: options.width || window.innerWidth,
        height: options.height || window.innerHeight,
        antialias: options.antialias ?? recommendedSettings.antialias,
        resolution: options.resolution ?? recommendedSettings.resolution,
        autoDensity: true,
        backgroundColor: bgColor,
        powerPreference: options.powerPreference ?? recommendedSettings.powerPreference,
        preserveDrawingBuffer: options.preserveDrawingBuffer ?? recommendedSettings.preserveDrawingBuffer,
        // Force WebGL1 if WebGL2 not available
        preferWebGLVersion: this.renderingMode === RenderingMode.WEBGL2 ? 2 : 1,
      });

      // Configure for psychology experiments
      this.app.stage.sortableChildren = true;
      this.app.stage.eventMode = 'static'; // Enable interaction

      // Style canvas
      this.app.canvas.id = 'psyforge-renderer';
      this.app.canvas.style.position = 'fixed';
      this.app.canvas.style.top = '0';
      this.app.canvas.style.left = '0';
      this.app.canvas.style.width = '100%';
      this.app.canvas.style.height = '100%';
      this.app.canvas.style.zIndex = '1000';

      // Add to document
      document.body.appendChild(this.app.canvas);

      // Handle window resize
      window.addEventListener('resize', this.handleResize.bind(this));

      // Store globally for BaseStimulus access
      (window as any).__psyforgePixiApp = this.app;

    } catch (error) {
      console.error('Failed to initialize WebGL renderer, falling back to Canvas2D:', error);

      // Fallback to Canvas2D if WebGL fails
      this.renderingMode = RenderingMode.CANVAS2D;
      this.canvas2DRenderer = new Canvas2DFallbackRenderer();
      this.canvas2DRenderer.setBackgroundColor(bgColorString);
      this.canvas2DRenderer.start();

      if (options.showCompatibilityWarnings !== false) {
        showCanvas2DWarning();
      }
    }
  }

  this.isInitialized = true;
}

