// Performance monitoring
getFPS(): number {
  if (this.app) {
    return this.app.ticker.FPS;
  } else if (this.canvas2DRenderer) {
    // Canvas2D doesn't provide easy FPS tracking
    return 60; // Assume target FPS
  }
  return 0;
}

getMemoryUsage(): { textureCount: number; textureMemory: number } {
  if (this.app) {
    const textures = PIXI.utils.TextureCache;
    let textureCount = 0;
    let textureMemory = 0;

    for (const key in textures) {
      const texture = textures[key];
      if (texture && texture.source) {
        textureCount++;
        textureMemory += texture.source.width * texture.source.height * 4; // RGBA
      }
    }

    return { textureCount, textureMemory };
  } else if (this.canvas2DRenderer) {
    const metrics = this.canvas2DRenderer.getPerformanceMetrics();
    return { 
      textureCount: metrics.stimulusCount, 
      textureMemory: 0 // Not easily measurable in Canvas2D
    };
  }

  return { textureCount: 0, textureMemory: 0 };
}

