import * as PIXI from 'pixi.js';
import type { TimelineContext } from '../core/Timeline.js';
import { BaseStimulus } from './BaseStimulus.js';
import { WebGLCompatibility, RenderingMode } from './compatibility/WebGLCompatibility.js';
import { Canvas2DFallbackRenderer, showCanvas2DWarning } from './compatibility/Canvas2DFallbackRenderer.js';

export interface RendererOptions {
  width?: number;
  height?: number;
  backgroundColor?: number | string;
  antialias?: boolean;
  resolution?: number;
  powerPreference?: 'high-performance' | 'low-power' | 'default';
  preserveDrawingBuffer?: boolean;
  forceCanvas2D?: boolean; // Force Canvas2D mode for testing
  showCompatibilityWarnings?: boolean; // Show warnings about reduced capabilities
}

export class StimulusRenderer {
  private static instance: StimulusRenderer;
  private app: PIXI.Application | null = null;
  private canvas2DRenderer: Canvas2DFallbackRenderer | null = null;
  private activeStimuli: Map<string, BaseStimulus> = new Map();
  private isInitialized = false;
  private renderingMode: RenderingMode = RenderingMode.UNSUPPORTED;

  private constructor() {
    // Detect capabilities on construction
    const capabilities = WebGLCompatibility.detectCapabilities();
    this.renderingMode = capabilities.mode;
  }

  static getInstance(): StimulusRenderer {
    if (!StimulusRenderer.instance) {
      StimulusRenderer.instance = new StimulusRenderer();
    }
    return StimulusRenderer.instance;
  }

  async initialize(options: RendererOptions = {}): Promise<void> {
    if (this.isInitialized) {
      return;
    }

    // Check if we should force Canvas2D
    if (options.forceCanvas2D) {
      this.renderingMode = RenderingMode.CANVAS2D;
    }

    // Show compatibility warnings if requested
    if (options.showCompatibilityWarnings !== false) {
      WebGLCompatibility.showCompatibilityWarning();
    }

    // Parse background color
    let bgColor = 0x000000;
    let bgColorString = '#000000';
    if (options.backgroundColor !== undefined) {
      if (typeof options.backgroundColor === 'string') {
        bgColor = parseInt(options.backgroundColor.replace('#', ''), 16);
        bgColorString = options.backgroundColor;
      } else {
        bgColor = options.backgroundColor;
        bgColorString = '#' + options.backgroundColor.toString(16).padStart(6, '0');
      }
    }

    // Initialize based on rendering mode
    if (this.renderingMode === RenderingMode.CANVAS2D) {
      // Use Canvas2D fallback
      this.canvas2DRenderer = new Canvas2DFallbackRenderer();
      this.canvas2DRenderer.setBackgroundColor(bgColorString);
      this.canvas2DRenderer.start();

      if (options.showCompatibilityWarnings !== false) {
        showCanvas2DWarning();
      }

      console.warn('Using Canvas2D fallback renderer - timing precision and effects limited');
    } else {
      // Use PIXI.js with WebGL
      try {
        // Get recommended settings based on capabilities
        const recommendedSettings = WebGLCompatibility.getRecommendedSettings();

        this.app = new PIXI.Application();

        await this.app.init({
          width: options.width || window.innerWidth,
          height: options.height || window.innerHeight,
          antialias: options.antialias ?? recommendedSettings.antialias,
          resolution: options.resolution ?? recommendedSettings.resolution,
          autoDensity: true,
          backgroundColor: bgColor,
          powerPreference: options.powerPreference ?? recommendedSettings.powerPreference,
          preserveDrawingBuffer: options.preserveDrawingBuffer ?? recommendedSettings.preserveDrawingBuffer,
          // Force WebGL1 if WebGL2 not available
          preferWebGLVersion: this.renderingMode === RenderingMode.WEBGL2 ? 2 : 1,
        });

        // Configure for psychology experiments
        this.app.stage.sortableChildren = true;
        this.app.stage.eventMode = 'static'; // Enable interaction

        // Style canvas
        this.app.canvas.id = 'psyforge-renderer';
        this.app.canvas.style.position = 'fixed';
        this.app.canvas.style.top = '0';
        this.app.canvas.style.left = '0';
        this.app.canvas.style.width = '100%';
        this.app.canvas.style.height = '100%';
        this.app.canvas.style.zIndex = '1000';

        // Add to document
        document.body.appendChild(this.app.canvas);

        // Handle window resize
        window.addEventListener('resize', this.handleResize.bind(this));

        // Store globally for BaseStimulus access
        (window as any).__psyforgePixiApp = this.app;

      } catch (error) {
        console.error('Failed to initialize WebGL renderer, falling back to Canvas2D:', error);

        // Fallback to Canvas2D if WebGL fails
        this.renderingMode = RenderingMode.CANVAS2D;
        this.canvas2DRenderer = new Canvas2DFallbackRenderer();
        this.canvas2DRenderer.setBackgroundColor(bgColorString);
        this.canvas2DRenderer.start();

        if (options.showCompatibilityWarnings !== false) {
          showCanvas2DWarning();
        }
      }
    }

    this.isInitialized = true;
  }

  private handleResize(): void {
    if (this.app) {
      this.app.renderer.resize(window.innerWidth, window.innerHeight);
    }
    // Canvas2D renderer handles its own resizing
  }

  async presentStimulus(stimulus: BaseStimulus, context: TimelineContext): Promise<void> {
    if (!this.isInitialized) {
      await this.initialize();
    }

    // Initialize and present the stimulus
    await stimulus.initialize(context);
    await stimulus.present(context);

    // Track active stimulus
    this.activeStimuli.set((stimulus as any).id, stimulus);
  }

  async removeStimulus(stimulus: BaseStimulus, context: TimelineContext): Promise<void> {
    await stimulus.remove(context);
    this.activeStimuli.delete((stimulus as any).id);
  }

  async clearAll(context: TimelineContext): Promise<void> {
    // Remove all active stimuli
    const removalPromises = Array.from(this.activeStimuli.values()).map(
      stimulus => stimulus.remove(context)
    );
    await Promise.all(removalPromises);
    this.activeStimuli.clear();

    // Clear the stage
    this.app.stage.removeChildren();
  }

  getRenderingMode(): RenderingMode {
    return this.renderingMode;
  }

  getCapabilities(): ReturnType<typeof WebGLCompatibility.detectCapabilities> {
    return WebGLCompatibility.detectCapabilities();
  }

  getApp(): PIXI.Application | null {
    return this.app;
  }

  getStage(): PIXI.Container | null {
    return this.app?.stage || null;
  }

  getCanvas(): HTMLCanvasElement | null {
    if (this.app) {
      return this.app.canvas;
    } else if (this.canvas2DRenderer) {
      return (this.canvas2DRenderer as any).canvas;
    }
    return null;
  }

  isWebGLAvailable(): boolean {
    return this.renderingMode === RenderingMode.WEBGL2 || 
           this.renderingMode === RenderingMode.WEBGL1;
  }

  isCanvas2DMode(): boolean {
    return this.renderingMode === RenderingMode.CANVAS2D;
  }

  // Utility methods for experiment control
  setBackgroundColor(color: number | string): void {
    if (this.app) {
      if (typeof color === 'string') {
        this.app.renderer.background.color = parseInt(color.replace('#', ''), 16);
      } else {
        this.app.renderer.background.color = color;
      }
    } else if (this.canvas2DRenderer) {
      const colorString = typeof color === 'string' ? color : '#' + color.toString(16).padStart(6, '0');
      this.canvas2DRenderer.setBackgroundColor(colorString);
    }
  }

  setCursorVisible(visible: boolean): void {
    const canvas = this.getCanvas();
    if (canvas) {
      canvas.style.cursor = visible ? 'auto' : 'none';
    }
  }

  async takeScreenshot(): Promise<string> {
    if (this.app) {
      // Render current frame
      this.app.render();

      // Get data URL
      const dataUrl = await this.app.renderer.extract.base64(this.app.stage);
      return dataUrl;
    } else if (this.canvas2DRenderer) {
      return await this.canvas2DRenderer.takeScreenshot();
    }

    throw new Error('No renderer available for screenshot');
  }

  getActiveStimuli(): BaseStimulus[] {
    return Array.from(this.activeStimuli.values());
  }

  getStimulusById(id: string): BaseStimulus | undefined {
    return this.activeStimuli.get(id);
  }

  // Performance monitoring
  getFPS(): number {
    if (this.app) {
      return this.app.ticker.FPS;
    } else if (this.canvas2DRenderer) {
      // Canvas2D doesn't provide easy FPS tracking
      return 60; // Assume target FPS
    }
    return 0;
  }

  getMemoryUsage(): { textureCount: number; textureMemory: number } {
    if (this.app) {
      const textures = PIXI.utils.TextureCache;
      let textureCount = 0;
      let textureMemory = 0;

      for (const key in textures) {
        const texture = textures[key];
        if (texture && texture.source) {
          textureCount++;
          textureMemory += texture.source.width * texture.source.height * 4; // RGBA
        }
      }

      return { textureCount, textureMemory };
    } else if (this.canvas2DRenderer) {
      const metrics = this.canvas2DRenderer.getPerformanceMetrics();
      return { 
        textureCount: metrics.stimulusCount, 
        textureMemory: 0 // Not easily measurable in Canvas2D
      };
    }

    return { textureCount: 0, textureMemory: 0 };
  }

  // Cleanup
  destroy(): void {
    window.removeEventListener('resize', this.handleResize.bind(this));

    // Clear all stimuli
    this.activeStimuli.clear();

    if (this.app) {
      // Destroy PIXI app
      this.app.destroy(true, { children: true, texture: true });

      // Remove from globals
      delete (window as any).__psyforgePixiApp;

      this.app = null;
    }

    if (this.canvas2DRenderer) {
      this.canvas2DRenderer.destroy();
      this.canvas2DRenderer = null;
    }

    this.isInitialized = false;
  }
}

