import { describe, it, expect, beforeEach, vi } from 'vitest';
import { Canvas2DFallbackRenderer, Canvas2DStimulus } from '../../src/stimuli/compatibility/Canvas2DFallbackRenderer';

describe('Canvas2DFallbackRenderer', () => {
  let renderer: Canvas2DFallbackRenderer;
  let mockCanvas: HTMLCanvasElement;
  let mockContext: CanvasRenderingContext2D;

  beforeEach(() => {
    // Create mock canvas and context
    mockContext = {
      fillRect: vi.fn(),
      strokeRect: vi.fn(),
      clearRect: vi.fn(),
      fillText: vi.fn(),
      drawImage: vi.fn(),
      save: vi.fn(),
      restore: vi.fn(),
      translate: vi.fn(),
      rotate: vi.fn(),
      scale: vi.fn(),
      beginPath: vi.fn(),
      moveTo: vi.fn(),
      lineTo: vi.fn(),
      closePath: vi.fn(),
      arc: vi.fn(),
      fill: vi.fn(),
      stroke: vi.fn(),
      fillStyle: '#000000',
      strokeStyle: '#000000',
      globalAlpha: 1,
      font: '24px Arial',
      textAlign: 'center',
      textBaseline: 'middle',
      lineWidth: 1,
      shadowColor: '',
      shadowBlur: 0,
      shadowOffsetX: 0,
      shadowOffsetY: 0
    } as any;

    mockCanvas = {
      getContext: vi.fn(() => mockContext),
      width: 800,
      height: 600,
      style: {},
      addEventListener: vi.fn(),
      removeEventListener: vi.fn(),
      remove: vi.fn(),
      toDataURL: vi.fn(() => 'data:image/png;base64,test')
    } as any;

    // Mock document methods
    vi.spyOn(document, 'createElement').mockReturnValue(mockCanvas);
    vi.spyOn(document.body, 'appendChild').mockImplementation(() => mockCanvas);

    renderer = new Canvas2DFallbackRenderer();
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  describe('initialization', () => {
    it('should create canvas element if not provided', () => {
      expect(document.createElement).toHaveBeenCalledWith('canvas');
      expect(mockCanvas.getContext).toHaveBeenCalledWith('2d');
    });

    it('should setup canvas styles', () => {
      expect(mockCanvas.id).toBe('psyforge-canvas2d-fallback');
      expect(mockCanvas.style.position).toBe('fixed');
      expect(mockCanvas.style.zIndex).toBe('1000');
    });

    it('should throw error if 2D context not available', () => {
      mockCanvas.getContext = vi.fn(() => null);
      expect(() => new Canvas2DFallbackRenderer()).toThrow('Canvas 2D context not available');
    });
  });

  describe('rendering', () => {
    it('should start and stop rendering loop', () => {
      renderer.start();
      expect(renderer['isRunning']).toBe(true);

      renderer.stop();
      expect(renderer['isRunning']).toBe(false);
    });

    it('should add and render text stimulus', () => {
      const textStimulus: Canvas2DStimulus = {
        id: 'text1',
        type: 'text',
        x: 100,
        y: 100,
        visible: true,
        alpha: 1,
        data: {
          text: 'Hello World',
          fontSize: 32,
          color: '#FFFFFF',
          fontFamily: 'Arial'
        }
      };

      renderer.addStimulus(textStimulus);
      renderer['render']();

      expect(mockContext.save).toHaveBeenCalled();
      expect(mockContext.translate).toHaveBeenCalledWith(100, 100);
      expect(mockContext.fillText).toHaveBeenCalledWith('Hello World', 0, 0);
      expect(mockContext.restore).toHaveBeenCalled();
    });

    it('should render shape stimulus', () => {
      const shapeStimulus: Canvas2DStimulus = {
        id: 'shape1',
        type: 'shape',
        x: 200,
        y: 200,
        width: 100,
        height: 100,
        visible: true,
        data: {
          shape: 'rectangle',
          fillColor: '#FF0000',
          strokeColor: '#000000',
          strokeWidth: 2
        }
      };

      renderer.addStimulus(shapeStimulus);
      renderer['render']();

      expect(mockContext.fillRect).toHaveBeenCalledWith(-50, -50, 100, 100);
      expect(mockContext.strokeRect).toHaveBeenCalledWith(-50, -50, 100, 100);
    });

    it('should skip invisible stimuli', () => {
      const stimulus: Canvas2DStimulus = {
        id: 'hidden1',
        type: 'text',
        x: 100,
        y: 100,
        visible: false,
        data: { text: 'Hidden' }
      };

      renderer.addStimulus(stimulus);
      renderer['render']();

      expect(mockContext.fillText).not.toHaveBeenCalled();
    });

    it('should apply transformations', () => {
      const stimulus: Canvas2DStimulus = {
        id: 'rotated1',
        type: 'shape',
        x: 100,
        y: 100,
        rotation: Math.PI / 4,
        alpha: 0.5,
        visible: true,
        data: {
          shape: 'rectangle',
          fillColor: '#00FF00'
        }
      };

      renderer.addStimulus(stimulus);
      renderer['render']();

      expect(mockContext.globalAlpha).toBe(0.5);
      expect(mockContext.rotate).toHaveBeenCalledWith(Math.PI / 4);
    });
  });

  describe('stimulus management', () => {
    it('should update stimulus properties', () => {
      const stimulus: Canvas2DStimulus = {
        id: 'test1',
        type: 'text',
        x: 100,
        y: 100,
        visible: true,
        data: { text: 'Test' }
      };

      renderer.addStimulus(stimulus);
      renderer.updateStimulus('test1', { x: 200, y: 200 });

      const updated = renderer['stimuli'].get('test1');
      expect(updated?.x).toBe(200);
      expect(updated?.y).toBe(200);
    });

    it('should remove stimulus', () => {
      const stimulus: Canvas2DStimulus = {
        id: 'test1',
        type: 'text',
        x: 100,
        y: 100,
        visible: true,
        data: { text: 'Test' }
      };

      renderer.addStimulus(stimulus);
      expect(renderer['stimuli'].size).toBe(1);

      renderer.removeStimulus('test1');
      expect(renderer['stimuli'].size).toBe(0);
    });

    it('should clear all stimuli', () => {
      renderer.addStimulus({ id: '1', type: 'text', x: 0, y: 0, data: {} });
      renderer.addStimulus({ id: '2', type: 'shape', x: 0, y: 0, data: {} });

      expect(renderer['stimuli'].size).toBe(2);

      renderer.clearStimuli();
      expect(renderer['stimuli'].size).toBe(0);
    });
  });

  describe('utility methods', () => {
    it('should set background color', () => {
      renderer.setBackgroundColor('#FF0000');
      expect(renderer['backgroundColor']).toBe('#FF0000');
    });

    it('should take screenshot', async () => {
      const dataUrl = await renderer.takeScreenshot();
      expect(dataUrl).toBe('data:image/png;base64,test');
      expect(mockCanvas.toDataURL).toHaveBeenCalledWith('image/png');
    });

    it('should get performance metrics', () => {
      renderer.addStimulus({ id: '1', type: 'text', x: 0, y: 0, data: {} });
      renderer.addStimulus({ id: '2', type: 'shape', x: 0, y: 0, data: {} });

      const metrics = renderer.getPerformanceMetrics();
      expect(metrics.stimulusCount).toBe(2);
      expect(metrics.fps).toBe(0); // Canvas2D doesn't track FPS
    });
  });

  describe('pixiToCanvas2D conversion', () => {
    it('should convert PIXI Text to Canvas2D stimulus', () => {
      const pixiText = {
        constructor: { name: 'Text' },
        uid: 123,
        x: 100,
        y: 200,
        rotation: 0,
        alpha: 1,
        visible: true,
        text: 'Hello',
        style: {
          fontSize: 24,
          fontFamily: 'Arial',
          fill: '#FFFFFF',
          align: 'center'
        }
      };

      const converted = Canvas2DFallbackRenderer.pixiToCanvas2D(pixiText);

      expect(converted).toEqual({
        id: '123',
        type: 'text',
        x: 100,
        y: 200,
        rotation: 0,
        alpha: 1,
        visible: true,
        data: {
          text: 'Hello',
          fontSize: 24,
          fontFamily: 'Arial',
          color: '#FFFFFF',
          align: 'center'
        }
      });
    });

    it('should convert PIXI Sprite to Canvas2D stimulus', () => {
      const mockImage = new Image();
      const pixiSprite = {
        constructor: { name: 'Sprite' },
        uid: 456,
        x: 50,
        y: 50,
        width: 100,
        height: 100,
        rotation: Math.PI / 2,
        alpha: 0.8,
        visible: true,
        texture: {
          source: {
            resource: mockImage
          }
        }
      };

      const converted = Canvas2DFallbackRenderer.pixiToCanvas2D(pixiSprite);

      expect(converted).toEqual({
        id: '456',
        type: 'image',
        x: 50,
        y: 50,
        width: 100,
        height: 100,
        rotation: Math.PI / 2,
        alpha: 0.8,
        visible: true,
        data: {
          image: mockImage
        }
      });
    });

    it('should return null for unsupported types', () => {
      const unsupported = {
        constructor: { name: 'Container' }
      };

      const converted = Canvas2DFallbackRenderer.pixiToCanvas2D(unsupported);
      expect(converted).toBeNull();
    });
  });

  describe('cleanup', () => {
    it('should destroy renderer properly', () => {
      renderer.start();
      renderer.addStimulus({ id: '1', type: 'text', x: 0, y: 0, data: {} });

      renderer.destroy();

      expect(renderer['isRunning']).toBe(false);
      expect(renderer['stimuli'].size).toBe(0);
      expect(mockCanvas.remove).toHaveBeenCalled();
    });
  });
});

