/**
 * API Surface Linter
 * Analyzes the ForgeScript API to detect complexity, inconsistencies, and potential issues
 */

import * as ts from 'typescript';
import { readFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

export interface APIMetrics {
  totalExports: number;
  publicMethods: number;
  publicClasses: number;
  publicInterfaces: number;
  builderMethods: number;
  deprecatedAPIs: number;
  complexityScore: number;
  recommendations: string[];
  warnings: string[];
  duplicatePatterns: string[];
}

export interface LintRule {
  name: string;
  check: (metrics: APIMetrics, ast: ts.SourceFile) => string[];
}

export class APILinter {
  private metrics: APIMetrics = {
    totalExports: 0,
    publicMethods: 0,
    publicClasses: 0,
    publicInterfaces: 0,
    builderMethods: 0,
    deprecatedAPIs: 0,
    complexityScore: 0,
    recommendations: [],
    warnings: [],
    duplicatePatterns: []
  };

  private rules: LintRule[] = [
    {
      name: 'api-surface-size',
      check: (metrics) => {
        const warnings = [];
        if (metrics.totalExports > 100) {
          warnings.push(`API surface too large: ${metrics.totalExports} exports (target: <100)`);
        }
        if (metrics.publicMethods > 200) {
          warnings.push(`Too many public methods: ${metrics.publicMethods} (target: <200)`);
        }
        return warnings;
      }
    },
    {
      name: 'builder-complexity',
      check: (metrics) => {
        const warnings = [];
        if (metrics.builderMethods > 50) {
          warnings.push(`Builder API too complex: ${metrics.builderMethods} methods (target: <50)`);
        }
        const avgMethodsPerClass = metrics.publicMethods / Math.max(metrics.publicClasses, 1);
        if (avgMethodsPerClass > 15) {
          warnings.push(`Classes too complex: ${avgMethodsPerClass.toFixed(1)} methods per class (target: <15)`);
        }
        return warnings;
      }
    },
    {
      name: 'deprecation-check',
      check: (metrics) => {
        const warnings = [];
        if (metrics.deprecatedAPIs > 10) {
          warnings.push(`Too many deprecated APIs: ${metrics.deprecatedAPIs} (target: <10)`);
        }
        return warnings;
      }
    },
    {
      name: 'naming-consistency',
      check: (metrics, ast) => {
        const warnings = [];
        const methodNames: string[] = [];

        // Collect all method names
        ts.forEachChild(ast, function visit(node) {
          if (ts.isMethodDeclaration(node) && node.name && ts.isIdentifier(node.name)) {
            methodNames.push(node.name.text);
          }
          ts.forEachChild(node, visit);
        });

        // Check for inconsistent patterns
        const patterns = {
          create: methodNames.filter(n => n.startsWith('create')).length,
          make: methodNames.filter(n => n.startsWith('make')).length,
          build: methodNames.filter(n => n.startsWith('build')).length,
          get: methodNames.filter(n => n.startsWith('get')).length,
          fetch: methodNames.filter(n => n.startsWith('fetch')).length
        };

        if (patterns.create > 0 && patterns.make > 0) {
          warnings.push('Inconsistent naming: both "create" and "make" prefixes used');
        }
        if (patterns.get > 0 && patterns.fetch > 0) {
          warnings.push('Inconsistent naming: both "get" and "fetch" prefixes used');
        }

        return warnings;
      }
    }
  ];

  /**
   * Analyze a TypeScript file for API metrics
   */
  analyzeFile(filePath: string): APIMetrics {
    const source = readFileSync(filePath, 'utf-8');
    const sourceFile = ts.createSourceFile(
      filePath,
      source,
      ts.ScriptTarget.Latest,
      true
    );

    this.collectMetrics(sourceFile);
    this.runLintRules(sourceFile);
    this.calculateComplexityScore();

    return this.metrics;
  }

  /**
   * Analyze multiple files
   */
  analyzeFiles(filePaths: string[]): APIMetrics {
    filePaths.forEach(path => {
      const source = readFileSync(path, 'utf-8');
      const sourceFile = ts.createSourceFile(
        path,
        source,
        ts.ScriptTarget.Latest,
        true
      );
      this.collectMetrics(sourceFile);
    });

    // Run rules after collecting all metrics
    const combinedAST = ts.createSourceFile(
      'combined.ts',
      '',
      ts.ScriptTarget.Latest,
      true
    );
    this.runLintRules(combinedAST);
    this.calculateComplexityScore();

    return this.metrics;
  }

  private collectMetrics(sourceFile: ts.SourceFile) {
    const visit = (node: ts.Node) => {
      // Count exports
      if (ts.isExportDeclaration(node) || ts.isExportAssignment(node)) {
        this.metrics.totalExports++;
      }

      // Count classes
      if (ts.isClassDeclaration(node) && node.modifiers?.some(m => m.kind === ts.SyntaxKind.ExportKeyword)) {
        this.metrics.publicClasses++;

        // Count methods in class
        node.members.forEach(member => {
          if (ts.isMethodDeclaration(member) && !this.isPrivate(member)) {
            this.metrics.publicMethods++;

            // Check if it's a builder method (returns 'this')
            if (member.type && ts.isThisTypeNode(member.type)) {
              this.metrics.builderMethods++;
            }
          }
        });
      }

      // Count interfaces
      if (ts.isInterfaceDeclaration(node) && node.modifiers?.some(m => m.kind === ts.SyntaxKind.ExportKeyword)) {
        this.metrics.publicInterfaces++;
      }

      // Count standalone functions
      if (ts.isFunctionDeclaration(node) && node.modifiers?.some(m => m.kind === ts.SyntaxKind.ExportKeyword)) {
        this.metrics.publicMethods++;
      }

      // Check for deprecated markers
      const deprecated = this.getJSDocTags(node).some(tag => tag.tagName.text === 'deprecated');
      if (deprecated) {
        this.metrics.deprecatedAPIs++;
      }

      ts.forEachChild(node, visit);
    };

    visit(sourceFile);
  }

  private runLintRules(sourceFile: ts.SourceFile) {
    this.rules.forEach(rule => {
      const warnings = rule.check(this.metrics, sourceFile);
      this.metrics.warnings.push(...warnings);
    });

    // Generate recommendations
    this.generateRecommendations();
  }

  private generateRecommendations() {
    const { metrics } = this;

    if (metrics.totalExports > 80) {
      metrics.recommendations.push(
        'Consider splitting the API into modules (e.g., core, advanced, experimental)'
      );
    }

    if (metrics.builderMethods > 40) {
      metrics.recommendations.push(
        'Consider using configuration objects instead of many builder methods'
      );
    }

    if (metrics.deprecatedAPIs > 5) {
      metrics.recommendations.push(
        'Schedule removal of deprecated APIs in next major version'
      );
    }

    if (metrics.publicClasses > 20) {
      metrics.recommendations.push(
        'Consider using factory functions instead of exposing many classes'
      );
    }

    // Check for duplicate functionality
    this.detectDuplicatePatterns();
  }

  private detectDuplicatePatterns() {
    // This is a simplified check - in reality would be more sophisticated
    const patterns = [
      ['create', 'make', 'build'],
      ['add', 'append', 'push'],
      ['remove', 'delete', 'pop'],
      ['get', 'fetch', 'retrieve']
    ];

    patterns.forEach(group => {
      const count = group.filter(pattern => 
        this.metrics.warnings.some(w => w.includes(pattern))
      ).length;

      if (count > 1) {
        this.metrics.duplicatePatterns.push(
          `Multiple patterns for same operation: ${group.join(', ')}`
        );
      }
    });
  }

  private calculateComplexityScore() {
    // Simple complexity calculation
    const weights = {
      exports: 1,
      methods: 0.5,
      classes: 2,
      interfaces: 1.5,
      builders: 0.3,
      deprecated: -2
    };

    this.metrics.complexityScore = 
      (this.metrics.totalExports * weights.exports) +
      (this.metrics.publicMethods * weights.methods) +
      (this.metrics.publicClasses * weights.classes) +
      (this.metrics.publicInterfaces * weights.interfaces) +
      (this.metrics.builderMethods * weights.builders) +
      (this.metrics.deprecatedAPIs * weights.deprecated);
  }

  private isPrivate(member: ts.ClassElement): boolean {
    return member.modifiers?.some(m => 
      m.kind === ts.SyntaxKind.PrivateKeyword ||
      m.kind === ts.SyntaxKind.ProtectedKeyword
    ) || false;
  }

  private getJSDocTags(node: ts.Node): readonly ts.JSDocTag[] {
    const jsDocs = (node as any).jsDoc as ts.JSDoc[] | undefined;
    if (!jsDocs) return [];

    return jsDocs.flatMap(doc => doc.tags || []);
  }

  /**
   * Generate a report of the API analysis
   */
  generateReport(): string {
    const { metrics } = this;

    let report = '# ForgeScript API Analysis Report\n\n';

    report += '## Metrics\n\n';
    report += `- Total Exports: ${metrics.totalExports}\n`;
    report += `- Public Methods: ${metrics.publicMethods}\n`;
    report += `- Public Classes: ${metrics.publicClasses}\n`;
    report += `- Public Interfaces: ${metrics.publicInterfaces}\n`;
    report += `- Builder Methods: ${metrics.builderMethods}\n`;
    report += `- Deprecated APIs: ${metrics.deprecatedAPIs}\n`;
    report += `- Complexity Score: ${metrics.complexityScore.toFixed(1)}\n\n`;

    if (metrics.warnings.length > 0) {
      report += '## Warnings\n\n';
      metrics.warnings.forEach(warning => {
        report += `- ⚠️  ${warning}\n`;
      });
      report += '\n';
    }

    if (metrics.duplicatePatterns.length > 0) {
      report += '## Duplicate Patterns\n\n';
      metrics.duplicatePatterns.forEach(pattern => {
        report += `- ${pattern}\n`;
      });
      report += '\n';
    }

    if (metrics.recommendations.length > 0) {
      report += '## Recommendations\n\n';
      metrics.recommendations.forEach(rec => {
        report += `- ${rec}\n`;
      });
      report += '\n';
    }

    report += '## Complexity Analysis\n\n';
    if (metrics.complexityScore < 100) {
      report += '✅ API complexity is well managed\n';
    } else if (metrics.complexityScore < 200) {
      report += '⚠️  API complexity is growing - consider refactoring\n';
    } else {
      report += '❌ API is too complex - refactoring recommended\n';
    }

    return report;
  }
}

// CLI runner
if (import.meta.url === `file://${process.argv[1]}`) {
  const linter = new APILinter();
  const __dirname = dirname(fileURLToPath(import.meta.url));

  // Analyze main API files
  const files = [
    resolve(__dirname, '../../index.ts'),
    resolve(__dirname, '../FluentExperimentBuilder.ts'),
    resolve(__dirname, '../../ForgeBuilder.ts')
  ];

  const metrics = linter.analyzeFiles(files);
  console.log(linter.generateReport());

  // Exit with error if complexity too high
  if (metrics.complexityScore > 200 || metrics.warnings.length > 5) {
    process.exit(1);
  }
}

