    });

    // Set timeline order
    const timelineOrder = validated.timelineOrder || validated.timelines.map(t => t.id);
    const orderedTimelines = timelineOrder
      .map(id => timelines.get(id))
      .filter((t): t is Timeline => t !== undefined);

    experiment.timeline(orderedTimelines);

    return experiment;
  }

  private static createStimulus(def: z.infer<typeof StimulusSchema>) {
    const id = crypto.randomUUID();

    switch (def.type) {
      case 'text':
        const text = new TextStimulus(id, def.content);
        if (def.duration) text.duration(def.duration);
        if (def.style?.fontSize) text.fontSize(def.style.fontSize);
        if (def.style?.color) text.color(def.style.color);
        if (def.style?.fontFamily) text.fontFamily(def.style.fontFamily);
        if (def.style?.position) text.position(def.style.position.x, def.style.position.y);
        return text;

      case 'image':
        const image = new ImageStimulus(id, def.src);
        if (def.duration) image.duration(def.duration);
        if (def.size) image.size(def.size.width, def.size.height);
        if (def.position) image.position(def.position.x, def.position.y);
        return image;

      case 'audio':
        const audio = new AudioStimulus(id, def.src);
        if (def.duration) audio.duration(def.duration);
        if (def.volume !== undefined) audio.volume(def.volume);
        return audio;

      case 'video':
        const video = new VideoStimulus(id, def.src);
        if (def.duration) video.duration(def.duration);
        if (def.size) video.size(def.size.width, def.size.height);
        return video;
    }
  }

  private static createResponse(def: z.infer<typeof ResponseSchema>) {
    const id = crypto.randomUUID();

    switch (def.type) {
      case 'keyboard':
        const keyboard = new KeyboardResponse(id);
        if (def.keys) keyboard.keys(def.keys);
        if (def.timeout) keyboard.timeout(def.timeout);
        if (def.correctKey) keyboard.correctAnswer(def.correctKey);
        return keyboard;

      case 'mouse':
        const mouse = new MouseResponse(id);
        if (def.timeout) mouse.timeout(def.timeout);
        return mouse;

      case 'touch':
        const touch = new TouchResponse(id);
        if (def.timeout) touch.timeout(def.timeout);
        return touch;
    }
  }

  private static createEvent(def: z.infer<typeof EventSchema>) {
    const id = crypto.randomUUID();

    switch (def.type) {
      case 'wait':
        return new WaitEvent(id, def.duration);

      case 'conditional':
        // For now, we'll skip conditional events in JSON format
        // They require code evaluation which is a security risk
        console.warn('Conditional events not supported in JSON format');
        return null;
    }
  }
}

/**
 * Convert Experiment to JSON format
 */
export class JSONExperimentExporter {
  static export(experiment: Experiment): ExperimentJSON {
    const timelines: z.infer<typeof TimelineSchema>[] = [];
    const timelineOrder: string[] = [];

    // Extract timelines
    const mainTimeline = (experiment as any).timelines?.[0];
    if (mainTimeline && mainTimeline.children) {
      mainTimeline.children.forEach((timeline: Timeline) => {
        const timelineJSON = this.exportTimeline(timeline);
        if (timelineJSON) {
          timelines.push(timelineJSON);
          timelineOrder.push(timeline.id);
        }
      });
    }

    return {
      version: '1.0',
      metadata: {
        title: (experiment as any)._title || 'Untitled Experiment',
        description: (experiment as any)._description,
        author: (experiment as any)._author,
        created: new Date().toISOString()
      },
      timelines,
      timelineOrder
    };
  }

  private static exportTimeline(timeline: Timeline): z.infer<typeof TimelineSchema> | null {
    const trials: z.infer<typeof TrialSchema>[] = [];

    // Group timeline items into trials
    let currentTrial: z.infer<typeof TrialSchema> | null = null;

    timeline.children.forEach(item => {
      if (this.isStimulus(item)) {
        // Start new trial with stimulus
        if (currentTrial) {
          trials.push(currentTrial);
        }
        currentTrial = {
          stimulus: this.exportStimulus(item),
          events: []
        };
      } else if (this.isResponse(item) && currentTrial) {
        // Add response to current trial
        currentTrial.response = this.exportResponse(item);
      } else if (this.isEvent(item) && currentTrial) {
        // Add event to current trial
        const event = this.exportEvent(item);
        if (event && currentTrial.events) {
          currentTrial.events.push(event);
        }
      }
    });

    // Add last trial
    if (currentTrial) {
      trials.push(currentTrial);
    }

    if (trials.length === 0) return null;

    return {
      id: timeline.id,
      trials,
      repeat: (timeline as any)._repeat,
      randomize: (timeline as any)._randomize,
      shuffle: (timeline as any)._shuffle
    };
  }

  private static isStimulus(item: any): boolean {
    return item instanceof TextStimulus || 
           item instanceof ImageStimulus || 
           item instanceof AudioStimulus || 
           item instanceof VideoStimulus;
  }

  private static isResponse(item: any): boolean {
    return item instanceof KeyboardResponse || 
           item instanceof MouseResponse || 
           item instanceof TouchResponse;
  }

  private static isEvent(item: any): boolean {
    return item instanceof WaitEvent;
  }

  private static exportStimulus(stimulus: any): z.infer<typeof StimulusSchema> {
    if (stimulus instanceof TextStimulus) {
      return {
        type: 'text',
        content: stimulus.content,
        duration: stimulus._duration
      };
    } else if (stimulus instanceof ImageStimulus) {
      return {
        type: 'image',
        src: stimulus.src,
        duration: stimulus._duration
      };
    } else if (stimulus instanceof AudioStimulus) {
      return {
        type: 'audio',
        src: stimulus.src,
        duration: stimulus._duration
      };
    } else if (stimulus instanceof VideoStimulus) {
      return {
        type: 'video',
        src: stimulus.src,
        duration: stimulus._duration
      };
    }

    throw new Error('Unknown stimulus type');
  }

  private static exportResponse(response: any): z.infer<typeof ResponseSchema> {
    if (response instanceof KeyboardResponse) {
      return {
        type: 'keyboard',
        keys: response._allowedKeys,
        timeout: response._timeout
      };
    } else if (response instanceof MouseResponse) {
      return {
        type: 'mouse',
        timeout: response._timeout
      };
    } else if (response instanceof TouchResponse) {
      return {
        type: 'touch',
        timeout: response._timeout
      };
    }

    throw new Error('Unknown response type');
  }

  private static exportEvent(event: any): z.infer<typeof EventSchema> | null {
    if (event instanceof WaitEvent) {
      return {
        type: 'wait',
        duration: event.duration
      };
    }

    return null;
  }
}

