/**
 * Security utilities for input sanitization and validation
 */

/**
 * Sanitize CSS color values to prevent injection attacks
 */
export function sanitizeColorValue(color: string): string | null {
  if (!color || typeof color !== 'string') {
    return null;
  }

  const trimmed = color.trim();

  // Check for dangerous patterns first
  if (trimmed.includes('javascript:') || 
      trimmed.includes('expression(') || 
      trimmed.includes('url(') ||
      trimmed.includes('<script') ||
      trimmed.includes('</script') ||
      trimmed.includes('&') ||
      trimmed.includes(';') ||
      trimmed.includes('\\')) {
    console.warn(`Potentially dangerous color value rejected: ${color}`);
    return null;
  }

  // Limit length to prevent buffer overflow-style attacks
  if (trimmed.length > 50) {
    console.warn(`Color value too long rejected: ${color}`);
    return null;
  }

  // Allow only safe color formats: hex, rgb, rgba, hsl, hsla, and named colors
  const colorRegex = /^(#[0-9a-fA-F]{3,8}|rgb\(\s*\d+\s*,\s*\d+\s*,\s*\d+\s*\)|rgba\(\s*\d+\s*,\s*\d+\s*,\s*\d+\s*,\s*[01]?\.?\d*\s*\)|hsl\(\s*\d+\s*,\s*\d+%\s*,\s*\d+%\s*\)|hsla\(\s*\d+\s*,\s*\d+%\s*,\s*\d+%\s*,\s*[01]?\.?\d*\s*\)|transparent|black|white|red|green|blue|yellow|purple|gray|grey|orange|pink|brown|cyan|magenta|lime|navy|olive|silver|teal|aqua|fuchsia|maroon)$/i;

  if (colorRegex.test(trimmed)) {
    return trimmed;
  }

  console.warn(`Invalid color value rejected: ${color}`);
  return null;
}

/**
 * Sanitize CSS cursor values to prevent injection attacks
 */
export function sanitizeCursorValue(cursor: string): string | null {
  if (!cursor || typeof cursor !== 'string') {
    return null;
  }

  const trimmed = cursor.trim();

  // Check for dangerous patterns first
  if (trimmed.includes('javascript:') || 
      trimmed.includes('expression(') || 
      trimmed.includes('url(') ||
      trimmed.includes('<script') ||
      trimmed.includes('</script') ||
      trimmed.includes('&') ||
      trimmed.includes(';') ||
      trimmed.includes('\\')) {
    console.warn(`Potentially dangerous cursor value rejected: ${cursor}`);
    return null;
  }

  // Limit length
  if (trimmed.length > 30) {
    console.warn(`Cursor value too long rejected: ${cursor}`);
    return null;
  }

  // Allow only valid CSS cursor values
  const validCursors = [
    'auto', 'default', 'none', 'context-menu', 'help', 'pointer', 'progress', 'wait',
    'cell', 'crosshair', 'text', 'vertical-text', 'alias', 'copy', 'move', 'no-drop',
    'not-allowed', 'grab', 'grabbing', 'e-resize', 'n-resize', 'ne-resize', 'nw-resize',
    's-resize', 'se-resize', 'sw-resize', 'w-resize', 'ew-resize', 'ns-resize', 'nesw-resize',
    'nwse-resize', 'col-resize', 'row-resize', 'all-scroll', 'zoom-in', 'zoom-out'
  ];

  const sanitizedCursor = trimmed.toLowerCase();

  if (validCursors.includes(sanitizedCursor)) {
    return sanitizedCursor;
  }

  console.warn(`Invalid cursor value rejected: ${cursor}`);
  return null;
}

/**
 * Sanitize font family values to prevent injection attacks
 */
export function sanitizeFontFamily(fontFamily: string): string | null {
  if (!fontFamily || typeof fontFamily !== 'string') {
    return null;
  }

  // Allow only safe font family formats - alphanumeric, spaces, hyphens, and common font names
  const fontRegex = /^[a-zA-Z0-9\s,\-'"]+$/;

  const trimmed = fontFamily.trim();

  // Check for dangerous patterns
  if (trimmed.includes('javascript:') || 
      trimmed.includes('expression(') || 
      trimmed.includes('url(') ||
      trimmed.includes('<') ||
      trimmed.includes('>') ||
      trimmed.includes('&') ||
      trimmed.includes(';')) {
    console.warn(`Potentially dangerous font family rejected: ${fontFamily}`);
    return null;
  }

  if (fontRegex.test(trimmed) && trimmed.length <= 100) {
    return trimmed;
  }

  console.warn(`Invalid font family value rejected: ${fontFamily}`);
  return null;
}

/**
 * Sanitize CSS class names to prevent injection attacks
 */
export function sanitizeClassName(className: string): string | null {
  if (!className || typeof className !== 'string') {
    return null;
  }

  // Allow only valid CSS class name characters
  const classRegex = /^[a-zA-Z0-9\s\-_]+$/;

  const trimmed = className.trim();

  if (classRegex.test(trimmed) && trimmed.length <= 50) {
    return trimmed;
  }

  console.warn(`Invalid class name rejected: ${className}`);
  return null;
}

/**
 * Sanitize arbitrary CSS style values to prevent injection attacks
 */
export function sanitizeStyleValue(property: string, value: string): string | null {
  if (!property || !value || typeof property !== 'string' || typeof value !== 'string') {
    return null;
  }

  const trimmedProperty = property.trim().toLowerCase();
  const trimmedValue = value.trim();

  // Block dangerous CSS properties
  const dangerousProperties = [
    'behavior', 'expression', 'javascript', 'vbscript', 'binding', 'import',
    'include', 'moz-binding', 'script', 'mozbinding'
  ];

  if (dangerousProperties.some(prop => trimmedProperty.includes(prop))) {
    console.warn(`Dangerous CSS property rejected: ${property}`);
    return null;
  }

  // Check for dangerous patterns in values
  if (trimmedValue.includes('javascript:') || 
      trimmedValue.includes('expression(') || 
      trimmedValue.includes('url(data:') ||
      trimmedValue.includes('<script') ||
      trimmedValue.includes('</script') ||
      trimmedValue.includes('on') ||
      trimmedValue.includes('\\')) {
    console.warn(`Potentially dangerous CSS value rejected: ${property}: ${value}`);
    return null;
  }

  // Limit value length
  if (trimmedValue.length > 200) {
    console.warn(`CSS value too long rejected: ${property}: ${value}`);
    return null;
  }

  return trimmedValue;
}

/**
 * Sanitize text content to prevent XSS attacks
 */
export function sanitizeTextContent(text: string): string {
  if (!text || typeof text !== 'string') {
    return '';
  }

  // Simple HTML entity encoding for basic XSS prevention
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/**
 * Sanitize numeric values to prevent injection through number conversion
 */
export function sanitizeNumericValue(value: number, min?: number, max?: number): number | null {
  if (typeof value !== 'number' || !isFinite(value)) {
    return null;
  }

  if (min !== undefined && value < min) {
    return null;
  }

  if (max !== undefined && value > max) {
    return null;
  }

  return value;
}

/**
 * Sanitize URL values to prevent dangerous URLs
 */
export function sanitizeUrl(url: string): string | null {
  if (!url || typeof url !== 'string') {
    return null;
  }

  const trimmed = url.trim();

  // Limit URL length
  if (trimmed.length > 2048) {
    console.warn(`URL too long rejected: ${url}`);
    return null;
  }

  // Allow only safe URL schemes
  const safeSchemes = ['http:', 'https:', 'data:image/', 'data:audio/', 'data:video/'];

  // Check for dangerous patterns
  if (trimmed.includes('javascript:') || 
      trimmed.includes('vbscript:') ||
      trimmed.includes('data:text/html') ||
      trimmed.includes('<script') ||
      trimmed.includes('</script') ||
      trimmed.includes('onload=') ||
      trimmed.includes('onerror=')) {
    console.warn(`Dangerous URL rejected: ${url}`);
    return null;
  }

  // Check if URL starts with a safe scheme
  const hasValidScheme = safeSchemes.some(scheme => trimmed.toLowerCase().startsWith(scheme));

  if (!hasValidScheme && !trimmed.startsWith('/') && !trimmed.startsWith('./')) {
    console.warn(`Invalid URL scheme rejected: ${url}`);
    return null;
  }

  return trimmed;
}

/**
 * Sanitize experiment metadata strings to prevent script injection
 */
export function sanitizeMetadataString(value: string, maxLength: number = 500): string | null {
  if (!value || typeof value !== 'string') {
    return null;
  }

  const trimmed = value.trim();

  // Check length limit
  if (trimmed.length > maxLength) {
    console.warn(`Metadata string too long (${trimmed.length} > ${maxLength}): ${value.substring(0, 50)}...`);
    return null;
  }

  // Check for dangerous patterns
  if (trimmed.includes('<script') ||
      trimmed.includes('</script') ||
      trimmed.includes('javascript:') ||
      trimmed.includes('onload=') ||
      trimmed.includes('onerror=') ||
      trimmed.includes('expression(') ||
      trimmed.includes('eval(') ||
      trimmed.includes('function(') ||
      trimmed.includes('\\x') ||
      trimmed.includes('\\u')) {
    console.warn(`Potentially dangerous metadata string rejected: ${value}`);
    return null;
  }

  // Basic HTML entity encoding for safety
  return trimmed
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

/**
 * Sanitize participant ID to prevent injection attacks
 */
export function sanitizeParticipantId(id: string): string | null {
  if (!id || typeof id !== 'string') {
    return null;
  }

  const trimmed = id.trim();

  // Check length (reasonable participant ID length)
  if (trimmed.length > 100) {
    console.warn(`Participant ID too long: ${id}`);
    return null;
  }

  // Allow only alphanumeric characters, hyphens, and underscores
  const idRegex = /^[a-zA-Z0-9\-_]+$/;

  if (idRegex.test(trimmed)) {
    return trimmed;
  }

  console.warn(`Invalid participant ID format rejected: ${id}`);
  return null;
}

