/**
 * Content Security Policy (CSP) implementation for ForgeScript experiments
 */

export interface CSPDirectives {
  'default-src'?: string[];
  'script-src'?: string[];
  'style-src'?: string[];
  'img-src'?: string[];
  'media-src'?: string[];
  'font-src'?: string[];
  'connect-src'?: string[];
  'frame-src'?: string[];
  'object-src'?: string[];
  'base-uri'?: string[];
  'form-action'?: string[];
  'frame-ancestors'?: string[];
  'report-uri'?: string;
  'report-to'?: string;
}

export interface CSPOptions {
  /** Enable report-only mode for testing */
  reportOnly?: boolean;
  /** Custom CSP directives */
  directives?: CSPDirectives;
  /** Nonce for inline scripts */
  nonce?: string;
  /** Enable strict dynamic CSP */
  strictDynamic?: boolean;
  /** Report endpoint URL */
  reportUri?: string;
}

export class ContentSecurityPolicy {
  private static instance: ContentSecurityPolicy;
  private nonce: string;
  private directives: CSPDirectives;
  private reportOnly: boolean;

  private constructor() {
    this.nonce = this.generateNonce();
    this.reportOnly = false;
    this.directives = this.getDefaultDirectives();
  }

  static getInstance(): ContentSecurityPolicy {
    if (!ContentSecurityPolicy.instance) {
      ContentSecurityPolicy.instance = new ContentSecurityPolicy();
    }
    return ContentSecurityPolicy.instance;
  }

  /**
   * Generate a secure nonce for inline scripts
   */
  private generateNonce(): string {
    const array = new Uint8Array(16);
    crypto.getRandomValues(array);
    return btoa(String.fromCharCode(...array))
      .replace(/[+/]/g, c => c === '+' ? '-' : '_')
      .replace(/=/g, '');
  }

  /**
   * Get default CSP directives for experiments
   */
  private getDefaultDirectives(): CSPDirectives {
    return {
      'default-src': ["'self'"],
      'script-src': ["'self'", `'nonce-${this.nonce}'`, "'strict-dynamic'"],
      'style-src': ["'self'", "'unsafe-inline'"], // Needed for dynamic styles
      'img-src': ["'self'", 'data:', 'blob:'],
      'media-src': ["'self'", 'data:', 'blob:'],
      'font-src': ["'self'", 'data:'],
      'connect-src': ["'self'", 'https://api.psyforge.org'],
      'frame-src': ["'none'"],
      'object-src': ["'none'"],
      'base-uri': ["'self'"],
      'form-action': ["'self'"],
      'frame-ancestors': ["'none'"],
    };
  }

  /**
   * Configure CSP options
   */
  configure(options: CSPOptions): void {
    if (options.reportOnly !== undefined) {
      this.reportOnly = options.reportOnly;
    }

    if (options.directives) {
      this.directives = { ...this.directives, ...options.directives };
    }

    if (options.nonce) {
      this.nonce = options.nonce;
      // Update script-src with new nonce
      if (this.directives['script-src']) {
        this.directives['script-src'] = this.directives['script-src']
          .filter(src => !src.startsWith("'nonce-"))
          .concat(`'nonce-${this.nonce}'`);
      }
    }

    if (options.strictDynamic && this.directives['script-src']) {
      if (!this.directives['script-src'].includes("'strict-dynamic'")) {
        this.directives['script-src'].push("'strict-dynamic'");
      }
    }

    if (options.reportUri) {
      this.directives['report-uri'] = options.reportUri;
    }
  }

  /**
   * Get the current nonce
   */
  getNonce(): string {
    return this.nonce;
  }

  /**
   * Generate CSP header value
   */
  getHeaderValue(): string {
    const parts: string[] = [];

    for (const [directive, values] of Object.entries(this.directives)) {
      if (Array.isArray(values)) {
        parts.push(`${directive} ${values.join(' ')}`);
      } else {
        parts.push(`${directive} ${values}`);
      }
    }

    return parts.join('; ');
  }

  /**
   * Get CSP header name
   */
  getHeaderName(): string {
    return this.reportOnly 
      ? 'Content-Security-Policy-Report-Only' 
      : 'Content-Security-Policy';
  }

  /**
   * Apply CSP to the document via meta tag
   */
  applyToDocument(): void {
    // Remove any existing CSP meta tags
    const existingCSP = document.querySelector('meta[http-equiv*="Content-Security-Policy"]');
    if (existingCSP) {
      existingCSP.remove();
    }

    // Create new CSP meta tag
    const meta = document.createElement('meta');
    meta.httpEquiv = this.getHeaderName();
    meta.content = this.getHeaderValue();
    document.head.appendChild(meta);

    // Log CSP application
    console.info('CSP applied:', this.getHeaderValue());
  }

  /**
   * Create inline script with nonce
   */
  createInlineScript(code: string): HTMLScriptElement {
    const script = document.createElement('script');
    script.setAttribute('nonce', this.nonce);
    script.textContent = code;
    return script;
  }

  /**
   * Create external script with integrity
   */
  createExternalScript(src: string, integrity?: string): HTMLScriptElement {
    const script = document.createElement('script');
    script.src = src;

    if (integrity) {
      script.integrity = integrity;
      script.crossOrigin = 'anonymous';
    }

    return script;
  }

  /**
   * Validate CSP directives
   */
  validate(): string[] {
    const warnings: string[] = [];

    // Check for unsafe-inline in script-src
    if (this.directives['script-src']?.includes("'unsafe-inline'")) {
      warnings.push("'unsafe-inline' in script-src weakens security");
    }

    // Check for unsafe-eval
    if (this.directives['script-src']?.includes("'unsafe-eval'")) {
      warnings.push("'unsafe-eval' in script-src is dangerous");
    }

    // Check for wildcard sources
    for (const [directive, values] of Object.entries(this.directives)) {
      if (Array.isArray(values) && values.some(v => v === '*')) {
        warnings.push(`Wildcard (*) in ${directive} is too permissive`);
      }
    }

    // Check for missing directives
    if (!this.directives['default-src']) {
      warnings.push("Missing default-src directive");
    }

    return warnings;
  }

  /**
   * Generate CSP report
   */
  generateReport(): string {
    const warnings = this.validate();

    let report = '# Content Security Policy Report\n\n';
    report += `## Current Policy\n\`\`\`\n${this.getHeaderValue()}\n\`\`\`\n\n`;

    if (warnings.length > 0) {
      report += '## Warnings\n';
      warnings.forEach(warning => {
        report += `- ⚠️  ${warning}\n`;
      });
      report += '\n';
    }

    report += '## Directives\n';
    for (const [directive, values] of Object.entries(this.directives)) {
      report += `- **${directive}**: ${Array.isArray(values) ? values.join(', ') : values}\n`;
    }

    return report;
  }

  /**
   * Reset to default CSP
   */
  reset(): void {
    this.nonce = this.generateNonce();
    this.directives = this.getDefaultDirectives();
    this.reportOnly = false;
  }
}

/**
 * CSP middleware for server applications
 */
export function cspMiddleware(options?: CSPOptions) {
  const csp = ContentSecurityPolicy.getInstance();

  if (options) {
    csp.configure(options);
  }

  return (req: any, res: any, next: any) => {
    // Add nonce to locals for template engines
    res.locals.cspNonce = csp.getNonce();

    // Set CSP header
    res.setHeader(csp.getHeaderName(), csp.getHeaderValue());

    next();
  };
}

/**
 * React/Svelte component helper
 */
export function useCSPNonce(): string {
  return ContentSecurityPolicy.getInstance().getNonce();
}

