    for (const [directive, values] of Object.entries(this.directives)) {
      report += `- **${directive}**: ${Array.isArray(values) ? values.join(', ') : values}\n`;
    }

    return report;
  }

  /**
   * Reset to default CSP
   */
  reset(): void {
    this.nonce = this.generateNonce();
    this.directives = this.getDefaultDirectives();
    this.reportOnly = false;
  }
}

/**
 * CSP middleware for server applications
 */
export function cspMiddleware(options?: CSPOptions) {
  const csp = ContentSecurityPolicy.getInstance();

  if (options) {
    csp.configure(options);
  }

  return (req: any, res: any, next: any) => {
    // Add nonce to locals for template engines
    res.locals.cspNonce = csp.getNonce();

    // Set CSP header
    res.setHeader(csp.getHeaderName(), csp.getHeaderValue());

    next();
  };
}

/**
 * React/Svelte component helper
 */
export function useCSPNonce(): string {
  return ContentSecurityPolicy.getInstance().getNonce();
}

