    }
    .metric {
      background: #f5f5f5;
      padding: 15px;
      border-radius: 4px;
      text-align: center;
    }
    .metric-value {
      font-size: 36px;
      font-weight: bold;
    }
    .vulnerability {
      background: white;
      border: 1px solid #ddd;
      padding: 15px;
      margin-bottom: 10px;
      border-radius: 4px;
    }
    .severity {
      display: inline-block;
      padding: 2px 8px;
      border-radius: 3px;
      color: white;
      font-weight: bold;
      text-transform: uppercase;
      font-size: 12px;
    }
    .critical { background: ${severityColors.critical}; }
    .high { background: ${severityColors.high}; }
    .moderate { background: ${severityColors.moderate}; }
    .low { background: ${severityColors.low}; }
  </style>
</head>
<body>
