/**
 * Consent Data Encryption for secure storage of participant consent information
 */

import { z } from 'zod';

// Consent data schema
export const ConsentDataSchema = z.object({
  participantId: z.string(),
  timestamp: z.date(),
  consentType: z.enum(['informed_consent', 'data_usage', 'audio_recording', 'video_recording', 'biometric_data']),
  granted: z.boolean(),
  details: z.object({
    studyId: z.string(),
    studyTitle: z.string(),
    researcherName: z.string(),
    institutionName: z.string(),
    ethicsApprovalNumber: z.string().optional(),
    dataRetentionPeriod: z.string(),
    withdrawalMethod: z.string(),
  }),
  signature: z.string().optional(),
  ipAddress: z.string().optional(),
  userAgent: z.string().optional(),
});

export type ConsentData = z.infer<typeof ConsentDataSchema>;

export interface EncryptedConsent {
  encrypted: string;
  iv: string;
  salt: string;
  algorithm: string;
  timestamp: Date;
}

export interface ConsentEncryptionOptions {
  /** Key derivation iterations (higher = more secure but slower) */
  iterations?: number;
  /** Salt length in bytes */
  saltLength?: number;
  /** Initialization vector length */
  ivLength?: number;
  /** Encryption algorithm */
  algorithm?: 'AES-GCM' | 'AES-CBC';
}

export class ConsentDataEncryption {
  private algorithm: 'AES-GCM' | 'AES-CBC';
  private iterations: number;
  private saltLength: number;
  private ivLength: number;

  constructor(options: ConsentEncryptionOptions = {}) {
    this.algorithm = options.algorithm || 'AES-GCM';
    this.iterations = options.iterations || 100000;
    this.saltLength = options.saltLength || 32;
    this.ivLength = options.ivLength || 16;
  }

  /**
   * Encrypt consent data using a password
   */
  async encryptConsent(
    consentData: ConsentData,
    password: string
  ): Promise<EncryptedConsent> {
    // Validate consent data
    const validated = ConsentDataSchema.parse(consentData);

    // Generate salt and IV
    const salt = crypto.getRandomValues(new Uint8Array(this.saltLength));
    const iv = crypto.getRandomValues(new Uint8Array(this.ivLength));

    // Derive key from password
    const key = await this.deriveKey(password, salt);

    // Convert data to JSON
    const dataString = JSON.stringify(validated);
    const encoder = new TextEncoder();
    const data = encoder.encode(dataString);

    // Encrypt data
    const encrypted = await crypto.subtle.encrypt(
      {
        name: this.algorithm,
        iv: iv,
      },
      key,
      data
    );

    return {
      encrypted: this.arrayBufferToBase64(encrypted),
      iv: this.arrayBufferToBase64(iv),
      salt: this.arrayBufferToBase64(salt),
      algorithm: this.algorithm,
      timestamp: new Date(),
    };
  }

  /**
   * Decrypt consent data using a password
   */
  async decryptConsent(
    encryptedConsent: EncryptedConsent,
    password: string
  ): Promise<ConsentData> {
    // Convert from base64
    const encrypted = this.base64ToArrayBuffer(encryptedConsent.encrypted);
    const iv = this.base64ToArrayBuffer(encryptedConsent.iv);
    const salt = this.base64ToArrayBuffer(encryptedConsent.salt);

    // Derive key from password
    const key = await this.deriveKey(password, new Uint8Array(salt));

    // Decrypt data
    const decrypted = await crypto.subtle.decrypt(
      {
        name: encryptedConsent.algorithm,
        iv: new Uint8Array(iv),
      },
      key,
      encrypted
    );

    // Convert back to JSON
    const decoder = new TextDecoder();
    const dataString = decoder.decode(decrypted);
    const data = JSON.parse(dataString);

    // Validate decrypted data
    return ConsentDataSchema.parse(data);
  }

  /**
   * Derive encryption key from password
   */
  private async deriveKey(
    password: string,
    salt: Uint8Array
  ): Promise<CryptoKey> {
    const encoder = new TextEncoder();
    const passwordData = encoder.encode(password);

    // Import password as key material
    const passwordKey = await crypto.subtle.importKey(
      'raw',
      passwordData,
      'PBKDF2',
      false,
      ['deriveKey']
    );

    // Derive AES key
    return crypto.subtle.deriveKey(
      {
        name: 'PBKDF2',
        salt: salt,
        iterations: this.iterations,
        hash: 'SHA-256',
      },
      passwordKey,
      {
        name: this.algorithm,
        length: 256,
      },
      false,
      ['encrypt', 'decrypt']
    );
  }

  /**
   * Convert ArrayBuffer to base64
   */
  private arrayBufferToBase64(buffer: ArrayBuffer): string {
    const bytes = new Uint8Array(buffer);
    let binary = '';
    bytes.forEach(byte => {
      binary += String.fromCharCode(byte);
    });
    return btoa(binary);
  }

  /**
   * Convert base64 to ArrayBuffer
   */
  private base64ToArrayBuffer(base64: string): ArrayBuffer {
    const binary = atob(base64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      bytes[i] = binary.charCodeAt(i);
    }
    return bytes.buffer;
  }

  /**
   * Generate secure consent token
   */
  generateConsentToken(): string {
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return this.arrayBufferToBase64(array.buffer)
      .replace(/[+/]/g, c => c === '+' ? '-' : '_')
      .replace(/=/g, '');
  }

  /**
   * Hash consent data for integrity verification
   */
  async hashConsent(consentData: ConsentData): Promise<string> {
    const dataString = JSON.stringify(ConsentDataSchema.parse(consentData));
    const encoder = new TextEncoder();
    const data = encoder.encode(dataString);

    const hash = await crypto.subtle.digest('SHA-256', data);
    return this.arrayBufferToBase64(hash);
  }

  /**
   * Create consent withdrawal record
   */
  async createWithdrawalRecord(
    participantId: string,
    studyId: string,
    reason?: string
  ): Promise<EncryptedConsent> {
    const withdrawalData: ConsentData = {
      participantId,
      timestamp: new Date(),
      consentType: 'data_usage',
      granted: false, // Withdrawal = consent no longer granted
      details: {
        studyId,
        studyTitle: 'Consent Withdrawal',
        researcherName: 'System Generated',
        institutionName: 'System Generated',
        dataRetentionPeriod: 'Immediate Deletion Requested',
        withdrawalMethod: 'Electronic Withdrawal',
      },
      signature: reason || 'Participant requested withdrawal',
    };

    // Use system-generated password for withdrawal records
    const systemPassword = await this.generateSystemPassword();
    return this.encryptConsent(withdrawalData, systemPassword);
  }

  /**
   * Generate system password for internal use
   */
  private async generateSystemPassword(): Promise<string> {
    // In production, this should use secure key management
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return this.arrayBufferToBase64(array.buffer);
  }

  /**
   * Validate consent is still valid
   */
  isConsentValid(consent: ConsentData, maxAgeInDays?: number): boolean {
    if (!consent.granted) {
      return false;
    }

    if (maxAgeInDays) {
      const consentDate = new Date(consent.timestamp);
      const now = new Date();
      const daysDiff = (now.getTime() - consentDate.getTime()) / (1000 * 60 * 60 * 24);

      if (daysDiff > maxAgeInDays) {
        return false;
      }
    }

    return true;
  }

  /**
   * Export consent data for compliance
   */
  async exportConsentForCompliance(
    consentData: ConsentData,
    includePersonalData: boolean = false
  ): Promise<string> {
    const exportData = { ...consentData };

    if (!includePersonalData) {
      // Remove potentially identifying information
      delete exportData.ipAddress;
      delete exportData.userAgent;
      exportData.participantId = await this.hashConsent(consentData);
    }

    return JSON.stringify(exportData, null, 2);
  }
}

/**
 * Consent storage interface
 */
export interface ConsentStorage {
  store(encryptedConsent: EncryptedConsent): Promise<void>;
  retrieve(participantId: string, studyId: string): Promise<EncryptedConsent | null>;
  delete(participantId: string, studyId: string): Promise<void>;
  listConsents(participantId: string): Promise<EncryptedConsent[]>;
}

/**
 * In-memory consent storage (for testing)
 */
export class InMemoryConsentStorage implements ConsentStorage {
  private storage = new Map<string, EncryptedConsent>();

  private getKey(participantId: string, studyId: string): string {
    return `${participantId}:${studyId}`;
  }

  async store(encryptedConsent: EncryptedConsent): Promise<void> {
    // In real implementation, extract IDs from encrypted data
    const key = `temp:${Date.now()}`;
    this.storage.set(key, encryptedConsent);
  }

  async retrieve(participantId: string, studyId: string): Promise<EncryptedConsent | null> {
    const key = this.getKey(participantId, studyId);
    return this.storage.get(key) || null;
  }

  async delete(participantId: string, studyId: string): Promise<void> {
    const key = this.getKey(participantId, studyId);
    this.storage.delete(key);
  }

  async listConsents(participantId: string): Promise<EncryptedConsent[]> {
    const consents: EncryptedConsent[] = [];
    for (const [key, consent] of this.storage.entries()) {
      if (key.startsWith(participantId + ':')) {
        consents.push(consent);
      }
    }
    return consents;
  }
}

