/**
 * Rate Limiting and Payload Size Validation for API protection
 */

export interface RateLimitConfig {
  /** Maximum requests per window */
  maxRequests: number;
  /** Time window in milliseconds */
  windowMs: number;
  /** Skip successful requests from counting */
  skipSuccessfulRequests?: boolean;
  /** Skip failed requests from counting */
  skipFailedRequests?: boolean;
  /** Key generator function */
  keyGenerator?: (context: any) => string;
  /** Handler for rate limit exceeded */
  handler?: (context: any) => void;
}

export interface PayloadLimitConfig {
  /** Maximum payload size in bytes */
  maxSize: number;
  /** Maximum string length for text fields */
  maxStringLength?: number;
  /** Maximum array length */
  maxArrayLength?: number;
  /** Maximum object depth */
  maxDepth?: number;
  /** Allowed content types */
  allowedContentTypes?: string[];
}

export interface RateLimitEntry {
  count: number;
  resetTime: number;
  firstRequest: number;
  blocked: boolean;
}

/**
 * Token bucket algorithm for rate limiting
 */
export class RateLimiter {
  private limits = new Map<string, RateLimitEntry>();
  private config: RateLimitConfig;
  private cleanupInterval: NodeJS.Timeout | null = null;

  constructor(config: RateLimitConfig) {
    this.config = config;

    // Start cleanup interval
    this.cleanupInterval = setInterval(() => {
      this.cleanup();
    }, Math.min(config.windowMs, 60000)); // Cleanup at least every minute
  }

  /**
   * Check if request should be rate limited
   */
  async checkLimit(context: any = {}): Promise<boolean> {
    const key = this.generateKey(context);
    const now = Date.now();

    let entry = this.limits.get(key);

    if (!entry || now > entry.resetTime) {
      // Create new entry or reset existing
      entry = {
        count: 1,
        resetTime: now + this.config.windowMs,
        firstRequest: now,
        blocked: false,
      };
      this.limits.set(key, entry);
      return true; // Allow first request
    }

    // Check if already blocked
    if (entry.blocked) {
      if (this.config.handler) {
        this.config.handler(context);
      }
      return false;
    }

    // Increment count
    entry.count++;

    // Check limit
    if (entry.count > this.config.maxRequests) {
      entry.blocked = true;
      if (this.config.handler) {
        this.config.handler(context);
      }
      return false;
    }

    return true;
  }

  /**
   * Reset limit for a specific key
   */
  resetLimit(context: any = {}): void {
    const key = this.generateKey(context);
    this.limits.delete(key);
  }

  /**
   * Get current limit status
   */
  getStatus(context: any = {}): RateLimitEntry | null {
    const key = this.generateKey(context);
    return this.limits.get(key) || null;
  }

  /**
   * Generate rate limit key
   */
  private generateKey(context: any): string {
    if (this.config.keyGenerator) {
      return this.config.keyGenerator(context);
    }

    // Default: use IP address or session ID
    return context.ip || context.sessionId || 'global';
  }

  /**
   * Clean up expired entries
   */
  private cleanup(): void {
    const now = Date.now();
    for (const [key, entry] of this.limits.entries()) {
      if (now > entry.resetTime) {
        this.limits.delete(key);
      }
    }
  }

  /**
   * Destroy rate limiter
   */
  destroy(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }
    this.limits.clear();
  }
}

/**
 * Payload validator for size and structure limits
 */
export class PayloadValidator {
  private config: PayloadLimitConfig;

  constructor(config: PayloadLimitConfig) {
    this.config = config;
  }

  /**
   * Validate payload size and structure
   */
  validate(payload: any, contentType?: string): { valid: boolean; error?: string } {
    // Check content type if specified
    if (contentType && this.config.allowedContentTypes) {
      if (!this.config.allowedContentTypes.includes(contentType)) {
        return {
          valid: false,
          error: `Content type '${contentType}' not allowed`,
        };
      }
    }

    // Check raw size for strings
    if (typeof payload === 'string') {
      const size = new TextEncoder().encode(payload).length;
      if (size > this.config.maxSize) {
        return {
          valid: false,
          error: `Payload size ${size} bytes exceeds maximum ${this.config.maxSize} bytes`,
        };
      }
      return { valid: true };
    }

    // Check JSON size
    try {
      const jsonString = JSON.stringify(payload);
      const size = new TextEncoder().encode(jsonString).length;

      if (size > this.config.maxSize) {
        return {
          valid: false,
          error: `Payload size ${size} bytes exceeds maximum ${this.config.maxSize} bytes`,
        };
      }
    } catch (error) {
      return {
        valid: false,
        error: 'Invalid JSON payload',
      };
    }

    // Validate structure
    const structureValidation = this.validateStructure(payload, 0);
    if (!structureValidation.valid) {
      return structureValidation;
    }

    return { valid: true };
  }

  /**
   * Validate payload structure recursively
   */
  private validateStructure(
    obj: any, 
    depth: number
  ): { valid: boolean; error?: string } {
    // Check depth
    if (this.config.maxDepth && depth > this.config.maxDepth) {
      return {
        valid: false,
        error: `Object depth ${depth} exceeds maximum ${this.config.maxDepth}`,
      };
    }

    // Check strings
    if (typeof obj === 'string' && this.config.maxStringLength) {
      if (obj.length > this.config.maxStringLength) {
        return {
          valid: false,
          error: `String length ${obj.length} exceeds maximum ${this.config.maxStringLength}`,
        };
      }
    }

    // Check arrays
    if (Array.isArray(obj)) {
      if (this.config.maxArrayLength && obj.length > this.config.maxArrayLength) {
        return {
          valid: false,
          error: `Array length ${obj.length} exceeds maximum ${this.config.maxArrayLength}`,
        };
      }

      // Validate array elements
      for (const item of obj) {
        const result = this.validateStructure(item, depth + 1);
        if (!result.valid) {
          return result;
        }
      }
    }

    // Check objects
    if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
      const keys = Object.keys(obj);

      // Validate object properties
      for (const key of keys) {
        const result = this.validateStructure(obj[key], depth + 1);
        if (!result.valid) {
          return result;
        }
      }
    }

    return { valid: true };
  }
}

/**
 * API rate limiter for specific endpoints
 */
export class APIRateLimiter {
  private limiters = new Map<string, RateLimiter>();
  private payloadValidator: PayloadValidator;

  constructor(payloadConfig: PayloadLimitConfig) {
    this.payloadValidator = new PayloadValidator(payloadConfig);
  }

  /**
   * Add rate limit for endpoint
   */
  addEndpoint(endpoint: string, config: RateLimitConfig): void {
    this.limiters.set(endpoint, new RateLimiter(config));
  }

  /**
   * Check rate limit for endpoint
   */
  async checkEndpoint(
    endpoint: string, 
    context: any = {}
  ): Promise<{ allowed: boolean; reason?: string }> {
    const limiter = this.limiters.get(endpoint);

    if (!limiter) {
      return { allowed: true }; // No limit configured
    }

    const allowed = await limiter.checkLimit(context);

    if (!allowed) {
      return {
        allowed: false,
        reason: 'Rate limit exceeded',
      };
    }

    return { allowed: true };
  }

  /**
   * Validate request payload
   */
  validatePayload(
    payload: any, 
    contentType?: string
  ): { valid: boolean; error?: string } {
    return this.payloadValidator.validate(payload, contentType);
  }

  /**
   * Get endpoint status
   */
  getEndpointStatus(endpoint: string, context: any = {}): RateLimitEntry | null {
    const limiter = this.limiters.get(endpoint);
    return limiter ? limiter.getStatus(context) : null;
  }

  /**
   * Reset endpoint limit
   */
  resetEndpoint(endpoint: string, context: any = {}): void {
    const limiter = this.limiters.get(endpoint);
    if (limiter) {
      limiter.resetLimit(context);
    }
  }

  /**
   * Destroy all limiters
   */
  destroy(): void {
    for (const limiter of this.limiters.values()) {
      limiter.destroy();
    }
    this.limiters.clear();
  }
}

/**
 * Pre-configured rate limiters
 */
export const RateLimitPresets = {
  /** Strict: 10 requests per minute */
  strict: {
    maxRequests: 10,
    windowMs: 60 * 1000,
  },

  /** Normal: 100 requests per minute */
  normal: {
    maxRequests: 100,
    windowMs: 60 * 1000,
  },

  /** Relaxed: 1000 requests per minute */
  relaxed: {
    maxRequests: 1000,
    windowMs: 60 * 1000,
  },

  /** Burst: 50 requests per second */
  burst: {
    maxRequests: 50,
    windowMs: 1000,
  },
};

/**
 * Pre-configured payload limits
 */
export const PayloadLimitPresets = {
  /** Small: 1MB max, suitable for simple experiments */
  small: {
    maxSize: 1024 * 1024, // 1MB
    maxStringLength: 10000,
    maxArrayLength: 1000,
    maxDepth: 10,
  },

  /** Normal: 10MB max, suitable for most experiments */
  normal: {
    maxSize: 10 * 1024 * 1024, // 10MB
    maxStringLength: 100000,
    maxArrayLength: 10000,
    maxDepth: 20,
  },

  /** Large: 100MB max, for data-intensive experiments */
  large: {
    maxSize: 100 * 1024 * 1024, // 100MB
    maxStringLength: 1000000,
    maxArrayLength: 100000,
    maxDepth: 30,
  },
};

/**
 * Express/Koa middleware factory
 */
export function createRateLimitMiddleware(
  endpoint: string,
  rateLimiter: APIRateLimiter
) {
  return async (req: any, res: any, next: any) => {
    // Check rate limit
    const context = {
      ip: req.ip || req.connection.remoteAddress,
      sessionId: req.session?.id,
      userId: req.user?.id,
    };

    const { allowed, reason } = await rateLimiter.checkEndpoint(endpoint, context);

    if (!allowed) {
      res.status(429).json({
        error: 'Too Many Requests',
        message: reason,
        retryAfter: 60, // seconds
      });
      return;
    }

    // Validate payload
    if (req.body) {
      const { valid, error } = rateLimiter.validatePayload(
        req.body,
        req.headers['content-type']
      );

      if (!valid) {
        res.status(400).json({
          error: 'Bad Request',
          message: error,
        });
        return;
      }
    }

    next();
  };
}

