#!/usr/bin/env node

/**
 * Security scanning CLI for CI/CD integration
 */

import { SecurityScanner } from '../src/security/SecurityScanner';
import { resolve } from 'path';

// Parse command line arguments
const args = process.argv.slice(2);
const options: any = {
  projectRoot: process.cwd(),
  verbose: false,
  output: 'json',
  failOn: 'high',
};

// Simple argument parser
for (let i = 0; i < args.length; i++) {
  const arg = args[i];

  switch (arg) {
    case '--help':
    case '-h':
      console.log(`
Security Scanner CLI

Usage: npm run security:scan [options]

Options:
  --path <dir>        Project directory to scan (default: current directory)
  --fail-on <level>   Fail on severity: low, medium, high, critical (default: high)
  --skip <scan>       Skip specific scans (comma-separated: dependencies,codePatterns,csp,secrets,permissions)
  --output <format>   Output format: json, markdown, html, junit (default: json)
  --output-file <file> Save report to file
  --verbose           Enable verbose logging
  --help             Show this help message

Examples:
  npm run security:scan
  npm run security:scan --fail-on critical --output markdown
  npm run security:scan --skip secrets,permissions --output-file report.json
  npm run security:scan --output junit --output-file security-report.xml
`);
      process.exit(0);

    case '--path':
      options.projectRoot = resolve(args[++i]);
      break;

    case '--fail-on':
      options.failOn = args[++i];
      break;

    case '--skip':
      options.skip = args[++i].split(',');
      break;

    case '--output':
      options.output = args[++i];
      break;

    case '--output-file':
      options.outputPath = resolve(args[++i]);
      break;

    case '--verbose':
      options.verbose = true;
      break;

    default:
      console.error(`Unknown option: ${arg}`);
      process.exit(1);
  }
}

// Run security scan
async function runScan() {
  console.log('🔍 Starting security scan...\n');

  try {
    const scanner = new SecurityScanner(options);
    const result = await scanner.scan();

    // Print summary
    console.log(`📊 Security Scan Summary:`);
    console.log(`   Status: ${result.passed ? '✅ PASSED' : '❌ FAILED'}`);
    console.log(`   Critical: ${result.summary.critical}`);
    console.log(`   High: ${result.summary.high}`);
    console.log(`   Medium: ${result.summary.medium}`);
    console.log(`   Low: ${result.summary.low}`);
    console.log(`   Total: ${result.summary.total}\n`);

    // Print scan details
    Object.entries(result.scans).forEach(([key, scan]) => {
      const icon = scan.passed ? '✅' : '❌';
      console.log(`${icon} ${scan.name}: ${scan.issues.length} issues (${scan.duration}ms)`);

      if (options.verbose && scan.issues.length > 0) {
        scan.issues.forEach(issue => {
          console.log(`   - [${issue.severity.toUpperCase()}] ${issue.message}`);
          if (issue.file) {
            console.log(`     File: ${issue.file}${issue.line ? `:${issue.line}` : ''}`);
          }
        });
      }
    });

    // Print recommendations
    if (result.recommendations.length > 0) {
      console.log('\n📋 Recommendations:');
      result.recommendations.forEach(rec => {
        console.log(`   ${rec}`);
      });
    }

    // Output to stdout if no file specified
    if (!options.outputPath && options.output === 'json') {
      console.log('\n📄 Full Report (JSON):');
      console.log(JSON.stringify(result, null, 2));
    }

    // Exit with appropriate code
    if (!result.passed) {
      console.error('\n❌ Security scan failed!');
      process.exit(1);
    } else {
      console.log('\n✅ Security scan passed!');
      process.exit(0);
    }

  } catch (error: any) {
    console.error('❌ Security scan error:', error.message);
    if (options.verbose) {
      console.error(error.stack);
    }
    process.exit(2);
  }
}

// Run the scan
runScan();

