```typescript
// Create withdrawal record
const withdrawal = await encryption.createWithdrawalRecord(
  participantId,
  studyId,
  'Participant requested data deletion'
);

// Store withdrawal and delete original consent
await consentStorage.store(withdrawal);
await consentStorage.delete(participantId, studyId);
