/**
 * Memory Profiler for monitoring and optimizing memory usage
 */

export interface MemorySnapshot {
  timestamp: Date;
  heapUsed: number;
  heapTotal: number;
  external: number;
  arrayBuffers: number;
  domNodes?: number;
  jsEventListeners?: number;
  detachedNodes?: number;
}

export interface MemoryMetrics {
  current: MemorySnapshot;
  baseline: MemorySnapshot;
  peak: MemorySnapshot;
  average: MemorySnapshot;
  samples: number;
  duration: number;
  leakSuspected: boolean;
  recommendations: string[];
}

export interface ProfilerOptions {
  /** Enable automatic profiling */
  enabled: boolean;
  /** Sampling interval in milliseconds */
  samplingInterval?: number;
  /** Memory threshold for warnings (MB) */
  warningThreshold?: number;
  /** Memory threshold for errors (MB) */
  errorThreshold?: number;
  /** Enable heap snapshots */
  enableSnapshots?: boolean;
  /** Enable DOM monitoring */
  enableDOMMonitoring?: boolean;
  /** Maximum samples to keep */
  maxSamples?: number;
}

/**
 * Memory profiler for experiment runtime monitoring
 */
export class MemoryProfiler {
  private enabled: boolean;
  private options: Required<ProfilerOptions>;
  private samples: MemorySnapshot[] = [];
  private baseline: MemorySnapshot | null = null;
  private peak: MemorySnapshot | null = null;
  private interval: NodeJS.Timeout | null = null;
  private startTime: number = 0;
  private observers: Set<(metrics: MemoryMetrics) => void> = new Set();

  constructor(options: ProfilerOptions = { enabled: true }) {
    this.enabled = options.enabled;
    this.options = {
      enabled: options.enabled,
      samplingInterval: options.samplingInterval || 1000,
      warningThreshold: options.warningThreshold || 100, // 100MB
      errorThreshold: options.errorThreshold || 500, // 500MB
      enableSnapshots: options.enableSnapshots ?? true,
      enableDOMMonitoring: options.enableDOMMonitoring ?? true,
      maxSamples: options.maxSamples || 1000,
    };
  }

  /**
   * Start memory profiling
   */
  start(): void {
    if (!this.enabled || this.interval) return;

    this.startTime = performance.now();
    this.baseline = this.captureSnapshot();
    this.peak = this.baseline;
    this.samples = [this.baseline];

    this.interval = setInterval(() => {
      this.sample();
    }, this.options.samplingInterval);

    // Force initial GC if available
    this.requestGarbageCollection();
  }

  /**
   * Stop memory profiling
   */
  stop(): void {
    if (this.interval) {
      clearInterval(this.interval);
      this.interval = null;
    }
  }

  /**
   * Take a memory sample
   */
  private sample(): void {
    const snapshot = this.captureSnapshot();
    this.samples.push(snapshot);

    // Update peak
    if (!this.peak || snapshot.heapUsed > this.peak.heapUsed) {
      this.peak = snapshot;
    }

    // Trim old samples
    if (this.samples.length > this.options.maxSamples) {
      this.samples.shift();
    }

    // Check thresholds
    const heapMB = snapshot.heapUsed / (1024 * 1024);
    if (heapMB > this.options.errorThreshold) {
      this.notifyObservers(this.getMetrics());
      console.error(`Memory usage critical: ${heapMB.toFixed(2)}MB`);
    } else if (heapMB > this.options.warningThreshold) {
      console.warn(`Memory usage high: ${heapMB.toFixed(2)}MB`);
    }

    // Detect potential leaks
    if (this.detectMemoryLeak()) {
      console.warn('Potential memory leak detected');
    }

    // Notify observers
    this.notifyObservers(this.getMetrics());
  }

  /**
   * Capture current memory snapshot
   */
  private captureSnapshot(): MemorySnapshot {
    const snapshot: MemorySnapshot = {
      timestamp: new Date(),
      heapUsed: 0,
      heapTotal: 0,
      external: 0,
      arrayBuffers: 0,
    };

    // Node.js environment
    if (typeof process !== 'undefined' && process.memoryUsage) {
      const usage = process.memoryUsage();
      snapshot.heapUsed = usage.heapUsed;
      snapshot.heapTotal = usage.heapTotal;
      snapshot.external = usage.external;
      snapshot.arrayBuffers = usage.arrayBuffers || 0;
    }
    // Browser environment
    else if (typeof performance !== 'undefined' && 'memory' in performance) {
      const memory = (performance as any).memory;
      if (memory) {
        snapshot.heapUsed = memory.usedJSHeapSize || 0;
        snapshot.heapTotal = memory.totalJSHeapSize || 0;
        snapshot.external = memory.totalJSHeapSize - memory.usedJSHeapSize;
        snapshot.arrayBuffers = 0; // Not available in browser
      }
    }

    // DOM monitoring (browser only)
    if (this.options.enableDOMMonitoring && typeof document !== 'undefined') {
      snapshot.domNodes = document.getElementsByTagName('*').length;

      // Count event listeners (Chrome DevTools API if available)
      if (typeof (window as any).getEventListeners !== 'undefined') {
        let listenerCount = 0;
        const allElements = document.getElementsByTagName('*');
        for (let i = 0; i < allElements.length; i++) {
          const listeners = (window as any).getEventListeners(allElements[i]);
          for (const event in listeners) {
            listenerCount += listeners[event].length;
          }
        }
        snapshot.jsEventListeners = listenerCount;
      }
    }

    return snapshot;
  }

  /**
   * Get current memory metrics
   */
  getMetrics(): MemoryMetrics {
    const current = this.samples[this.samples.length - 1] || this.captureSnapshot();
    const average = this.calculateAverage();
    const duration = performance.now() - this.startTime;

    return {
      current,
      baseline: this.baseline || current,
      peak: this.peak || current,
      average,
      samples: this.samples.length,
      duration,
      leakSuspected: this.detectMemoryLeak(),
      recommendations: this.generateRecommendations(),
    };
  }

  /**
   * Calculate average memory usage
   */
  private calculateAverage(): MemorySnapshot {
    if (this.samples.length === 0) {
      return this.captureSnapshot();
    }

    const sum = this.samples.reduce(
      (acc, sample) => ({
        heapUsed: acc.heapUsed + sample.heapUsed,
        heapTotal: acc.heapTotal + sample.heapTotal,
        external: acc.external + sample.external,
        arrayBuffers: acc.arrayBuffers + sample.arrayBuffers,
        domNodes: (acc.domNodes || 0) + (sample.domNodes || 0),
        jsEventListeners: (acc.jsEventListeners || 0) + (sample.jsEventListeners || 0),
      }),
      {
        heapUsed: 0,
        heapTotal: 0,
        external: 0,
        arrayBuffers: 0,
        domNodes: 0,
        jsEventListeners: 0,
      }
    );

    const count = this.samples.length;
    return {
      timestamp: new Date(),
      heapUsed: sum.heapUsed / count,
      heapTotal: sum.heapTotal / count,
      external: sum.external / count,
      arrayBuffers: sum.arrayBuffers / count,
      domNodes: sum.domNodes ? sum.domNodes / count : undefined,
      jsEventListeners: sum.jsEventListeners ? sum.jsEventListeners / count : undefined,
    };
  }

  /**
   * Detect potential memory leaks
   */
  private detectMemoryLeak(): boolean {
    if (this.samples.length < 10) return false;

    // Check for consistent growth over last 10 samples
    const recentSamples = this.samples.slice(-10);
    let growthCount = 0;

    for (let i = 1; i < recentSamples.length; i++) {
      if (recentSamples[i].heapUsed > recentSamples[i - 1].heapUsed) {
        growthCount++;
      }
    }

    // If memory grew in 80% of samples, suspect a leak
    return growthCount >= 8;
  }

  /**
   * Generate optimization recommendations
   */
  private generateRecommendations(): string[] {
    const recommendations: string[] = [];
    const metrics = this.getMetrics();
    const heapMB = metrics.current.heapUsed / (1024 * 1024);

    // High memory usage
    if (heapMB > this.options.warningThreshold) {
      recommendations.push('Consider reducing stimulus complexity or preloading');
      recommendations.push('Enable resource cleanup between trials');
    }

    // Memory leak suspected
    if (metrics.leakSuspected) {
      recommendations.push('Check for unreleased event listeners');
      recommendations.push('Verify stimulus cleanup in trial transitions');
      recommendations.push('Review timeline object retention');
    }

    // High DOM nodes
    if (metrics.current.domNodes && metrics.current.domNodes > 5000) {
      recommendations.push('Excessive DOM nodes detected - consider virtualization');
    }

    // High event listeners
    if (metrics.current.jsEventListeners && metrics.current.jsEventListeners > 1000) {
      recommendations.push('Too many event listeners - use event delegation');
    }

    // Array buffer usage
    if (metrics.current.arrayBuffers > 50 * 1024 * 1024) {
      recommendations.push('High ArrayBuffer usage - consider streaming large data');
    }

    return recommendations;
  }

  /**
   * Force garbage collection if available
   */
  requestGarbageCollection(): void {
    if (typeof global !== 'undefined' && (global as any).gc) {
      (global as any).gc();
    } else if (typeof window !== 'undefined' && (window as any).gc) {
      (window as any).gc();
    }
  }

  /**
   * Take heap snapshot (Chrome DevTools Protocol)
   */
  async takeHeapSnapshot(): Promise<ArrayBuffer | null> {
    if (!this.options.enableSnapshots) return null;

    // This requires Chrome DevTools Protocol
    // In a real implementation, this would connect to CDP
    console.info('Heap snapshot requested - requires DevTools protocol');
    return null;
  }

  /**
   * Subscribe to memory metrics updates
   */
  subscribe(callback: (metrics: MemoryMetrics) => void): () => void {
    this.observers.add(callback);
    return () => this.observers.delete(callback);
  }

  /**
   * Notify all observers
   */
  private notifyObservers(metrics: MemoryMetrics): void {
    this.observers.forEach(callback => callback(metrics));
  }

  /**
   * Reset profiler
   */
  reset(): void {
    this.stop();
    this.samples = [];
    this.baseline = null;
    this.peak = null;
    this.startTime = 0;
  }

  /**
   * Enable/disable profiler
   */
  setEnabled(enabled: boolean): void {
    this.enabled = enabled;
    if (!enabled) {
      this.stop();
    }
  }

  /**
   * Export metrics as JSON
   */
  exportMetrics(): string {
    return JSON.stringify(this.getMetrics(), null, 2);
  }

  /**
   * Generate memory report
   */
  generateReport(): string {
    const metrics = this.getMetrics();
    const heapMB = metrics.current.heapUsed / (1024 * 1024);
    const peakMB = metrics.peak.heapUsed / (1024 * 1024);
    const baselineMB = metrics.baseline.heapUsed / (1024 * 1024);

    let report = '# Memory Profile Report\n\n';
    report += `## Summary\n`;
    report += `- Current Heap: ${heapMB.toFixed(2)}MB\n`;
    report += `- Peak Heap: ${peakMB.toFixed(2)}MB\n`;
    report += `- Baseline: ${baselineMB.toFixed(2)}MB\n`;
    report += `- Growth: ${(heapMB - baselineMB).toFixed(2)}MB\n`;
    report += `- Duration: ${(metrics.duration / 1000).toFixed(1)}s\n`;
    report += `- Samples: ${metrics.samples}\n`;
    report += `- Leak Suspected: ${metrics.leakSuspected ? 'Yes' : 'No'}\n\n`;

    if (metrics.current.domNodes) {
      report += `## DOM Metrics\n`;
      report += `- DOM Nodes: ${metrics.current.domNodes}\n`;
      if (metrics.current.jsEventListeners) {
        report += `- Event Listeners: ${metrics.current.jsEventListeners}\n`;
      }
      report += '\n';
    }

    if (metrics.recommendations.length > 0) {
      report += `## Recommendations\n`;
      metrics.recommendations.forEach(rec => {
        report += `- ${rec}\n`;
      });
    }

    return report;
  }
}

